function getQuestionTypeMeta(typeName: string) {
  switch (typeName) {
    case "SINGLE_CHOICE":
    case "MCQ":
      return {
        id: "single-choice",
        name: typeName === "SINGLE_CHOICE" ? "SINGLE_CHOICE" : "MCQ",
        gradingStrategy: "BINARY",
        hasOptions: true,
        supportsAi: false,
        isManualOnly: false,
        defaultMaxScore: 1,
        description: "Single correct answer from multiple options",
      };
    case "MULTIPLE_CHOICE":
    case "Multiple Choice":
      return {
        id: "multiple-choice",
        name:
          typeName === "MULTIPLE_CHOICE"
            ? "MULTIPLE_CHOICE"
            : "Multiple Choice",
        gradingStrategy: "DEDUCTIVE",
        hasOptions: true,
        supportsAi: false,
        isManualOnly: false,
        defaultMaxScore: 1,
        description: "Multiple correct answers can be selected.",
      };
    case "TRUE_FALSE":
    case "True/False":
      return {
        id: "boolean",
        name: typeName === "TRUE_FALSE" ? "TRUE_FALSE" : "True/False",
        gradingStrategy: "BINARY",
        hasOptions: true,
        supportsAi: false,
        isManualOnly: false,
        defaultMaxScore: 1,
        description: "Binary statement validation with a single correct state.",
      };
    case "Short Answer":
      return {
