          typeName === "FILL_IN_THE_BLANK"
            ? "FILL_IN_THE_BLANK"
            : "Fill-in-blank",
        gradingStrategy: "DEDUCTIVE",
        hasOptions: false,
        supportsAi: false,
        isManualOnly: false,
        defaultMaxScore: 3,
        description:
          "Learner fills one or more blanks in a sentence or template.",
      };
    case "Matching":
      return {
        id: "matching",
        name: "Matching",
        gradingStrategy: "DEDUCTIVE",
        hasOptions: false,
        supportsAi: false,
        isManualOnly: false,
