      <ActionConfirmModal
        open={showArchiveModal}
        onClose={() => setShowArchiveModal(false)}
        onConfirm={handleArchive}
        title="Archive Assessment"
        description={<>Are you sure you want to archive <strong>{actualTitle}</strong>? It will no longer be active.</>}
        confirmText="Archive"
        isPending={isPending}
        variant="destructive"
      />
    </section>
