    setRetryingIds((prev) => ({ ...prev, [entryId]: true }));
    try {
      const success = await retryAIGrading(data.assessment.id, data.answerSheet.id, entryId);
      if (success) {
        alert("AI Grading retry queued. Please refresh shortly.");
