                    <div className="grid gap-4 lg:grid-cols-3">
                      <div className="rounded-xl border border-border bg-white p-4">
                        <p className="text-xs font-semibold uppercase tracking-[0.18em] text-inkd">Score awarded</p>
                        <p className="mt-2 text-lg font-bold text-primary">{entry.scoreAwarded}</p>
                      </div>
                      <div className="rounded-xl border border-border bg-white p-4">
                        <p className="text-xs font-semibold uppercase tracking-[0.18em] text-inkd">Is correct</p>
                        <p className="mt-2 text-lg font-bold text-primary">
                          {entry.isCorrect == null ? "Not set" : entry.isCorrect ? "Yes" : "No"}
                        </p>
                      </div>
                      <div className="rounded-xl border border-border bg-white p-4">
                        <p className="text-xs font-semibold uppercase tracking-[0.18em] text-inkd">Review status</p>
                        <div className="mt-2">
                          {entry.gradingStatus === "PENDING" ? (
                            <div className="inline-flex items-center gap-2 text-orange-700">
                              <ShieldAlert className="h-4 w-4" />
                              <span className="font-semibold">Awaiting manual review</span>
                            </div>
                          ) : (
                            <div className="inline-flex items-center gap-2 text-green-700">
                              <CheckCircle2 className="h-4 w-4" />
                              <span className="font-semibold">{entry.gradingStatus}</span>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  )}
                </CardContent>
              </Card>
            );
          })}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import { CheckCircle2, Clock3, Radio } from "lucide-react";
import type { AssessmentCatalogItem } from "@/src/types";
import { QuestionRenderer } from "../renderers/QuestionRenderer";
import type { QuestionRendererValue } from "../renderers/types";
import { ScreenShell } from "./SessionShared";
import { JoinFinal } from "./join/JoinFinal";
import { JoinLobby } from "./join/JoinLobby";
import { JoinResult } from "./join/JoinResult";
import { JoinWaitingState } from "./join/JoinWaitingState";
import { realtimeEvents } from '@/src/lib/session/realtime.events';
import type { JoinPhase } from '@/src/types/session.types';
import {
  buildQuestionRounds,
  hasAnswerResponse,
  isCorrectAnswerResponse,
  requiresParticipantIdentity,
} from '@/src/lib/session/session.utils';
import { useRealtimeSession, type RealtimeSessionReturn } from "@/src/hooks/use-realtime-session";
import { RoomRole } from "@/src/types/runtime.types";
import { joinRealTimeSessionAction } from "@/src/lib/actions/assessment.actions";
import { toast } from "sonner";

const QUESTION_DURATION_SECONDS = 30;
const SPEED_BONUS_RATIO = 0.5;

export function EnterRealTimeScreen({
  assessment,
  embedded,
  session: externalSession,
  onPreviewParticipantJoined,
}: {
  assessment: AssessmentCatalogItem;
  embedded?: boolean;
  session?: RealtimeSessionReturn;
  onPreviewParticipantJoined?: (participant: { id: string; name: string }) => void;
}) {
  const internalSession = useRealtimeSession({ enabled: !externalSession });
  const activeSession = externalSession || internalSession;
  const rounds = useMemo(
    () =>
      buildQuestionRounds([
        {
          id: `${assessment.id}-join-question-1`,
          question: "Sample live question visible to participants before the round opens.",
          type: "MULTIPLE_CHOICE",
          points: 100,
        },
        {
          id: `${assessment.id}-join-question-2`,
          question: "Second live question shown after the host advances to the next reveal.",
          type: "MULTIPLE_CHOICE",
          points: 120,
        },
      ]),
    [assessment.id],
  );
  const requiresEntry = assessment.settings?.participantIdentity !== "ANONYMOUS";
  const requiresIdentity = requiresParticipantIdentity(assessment.settings?.participantIdentity || "EXTERNAL");

  const [displayName, setDisplayName] = useState("");
  const [email, setEmail] = useState("");
  const [questionIndex, setQuestionIndex] = useState(0);
  const [timerSeconds, setTimerSeconds] = useState(12);
  const [answerValue, setAnswerValue] = useState<QuestionRendererValue>(null);
  const [totalScore, setTotalScore] = useState(0);
  const [streakCount, setStreakCount] = useState(0);
  const [participantId, setParticipantId] = useState<string | null>(null);
  const [lastAwardedPoints, setLastAwardedPoints] = useState(0);
  const [submittedSpeedBonus, setSubmittedSpeedBonus] = useState(0);
  const awardedQuestionRef = useRef<string | null>(null);
  const backendScoreAppliedQuestionRef = useRef<string | null>(null);
  const scoreBeforeQuestionRef = useRef(0);
  const totalScoreRef = useRef(0);

  const { isConnected, roomState, joinRoom, emitSubmitAnswer } = activeSession;

  const currentRound = roomState.currentQuestion || rounds[0];
  const phase = roomState.phase;
  const questionNumber = roomState.questionNumber || questionIndex + 1;
  const totalQuestions = roomState.totalQuestions || rounds.length;
  const currentPoints = Number.isFinite(Number(currentRound.points))
    ? Number(currentRound.points)
    : 0;
  const timerProgressPercent = Math.max(
    0,
    Math.min(100, (timerSeconds / QUESTION_DURATION_SECONDS) * 100),
  );
  const hasTimedOut = phase === "active" && timerSeconds <= 0;
  const speedBonus = getRealtimeSpeedBonus(currentPoints, timerSeconds);
  const isLobbyPhase = phase === "lobby";
  const revealedCorrect = isAnswerCorrectFromReveal(roomState.questionResults?.correct, answerValue);

  useEffect(() => {
    totalScoreRef.current = totalScore;
  }, [totalScore]);

  // Reset local state when a new question starts
  useEffect(() => {
    if (phase === "active") {
      setTimerSeconds(QUESTION_DURATION_SECONDS);
      setAnswerValue(null);
      setLastAwardedPoints(0);
      setSubmittedSpeedBonus(0);
      awardedQuestionRef.current = null;
      backendScoreAppliedQuestionRef.current = null;
      scoreBeforeQuestionRef.current = totalScoreRef.current;
      setQuestionIndex(Math.max(0, (roomState.questionNumber || 1) - 1));
    }
  }, [phase, currentRound?.id, roomState.questionNumber]);

  useEffect(() => {
    if (phase !== "active" || !roomState.endTime) return;

    const tick = () => {
      const remaining = Math.max(
        0,
        Math.floor((new Date(roomState.endTime!).getTime() - Date.now()) / 1000),
      );
      setTimerSeconds(remaining);
    };

    tick();
    const intervalId = window.setInterval(tick, 1000);
    return () => window.clearInterval(intervalId);
  }, [phase, roomState.endTime]);

  async function joinLobby() {
    if (requiresIdentity && (displayName.trim().length === 0 || email.trim().length === 0)) {
      return;
    }

    let createdParticipantId: string | undefined = undefined;
    if (displayName.trim().length > 0) {
      try {
        const payload: any = { name: displayName };
        if (email.trim().length > 0) {
          payload.email = email;
        }

        const pRes = await joinRealTimeSessionAction(assessment.id, payload);
        if (!pRes.success) {
          throw new Error(pRes.error);
        }

        createdParticipantId =
          pRes.data?.id ||
          pRes.data?.data?.id ||
          pRes.data?.data?.data?.id ||
          pRes.data?.participant?.id ||
          pRes.data?.data?.participant?.id;
        setParticipantId(createdParticipantId || null);
      } catch (err: any) {
        console.error("Participant registration failed:", err);
        const msg = err?.response?.data?.message || err.message || "Failed to register participant details";
        toast.error(typeof msg === 'string' ? msg : JSON.stringify(msg));
        return;
      }
    }

    if (!isConnected) {
      toast.error("Realtime connection is still starting. Please try again in a moment.");
      return;
    }

    const participantName = displayName.trim() || "Anonymous";
    const roomParticipantId =
      createdParticipantId ||
      `preview-${participantName.toLowerCase().replace(/[^a-z0-9]+/g, "-")}-${Date.now()}`;

    setParticipantId(roomParticipantId);
    onPreviewParticipantJoined?.({ id: roomParticipantId, name: participantName });
    joinRoom(assessment.id, RoomRole.PARTICIPANT, roomParticipantId, participantName);
  }

  const [submitted, setSubmitted] = useState(false);

  function selectAnswer(value: QuestionRendererValue) {
    if (submitted) return; // prevent changing after submit
    setAnswerValue(value);
  }

  function handleSubmit() {
    if (!hasAnswerResponse(currentRound, answerValue) || submitted || hasTimedOut) return;
    setSubmitted(true);
    scoreBeforeQuestionRef.current = totalScore;
    const roundSpeedBonus = getRealtimeSpeedBonus(currentPoints, timerSeconds);
    setSubmittedSpeedBonus(roundSpeedBonus);

    if (participantId) {
      const timeSpentSecs = QUESTION_DURATION_SECONDS - timerSeconds;
      emitSubmitAnswer(answerValue, timeSpentSecs);
    }
  }

  // Reset submitted state when new question arrives
  useEffect(() => {
    if (phase === "active") {
      setSubmitted(false);
    }
  }, [phase, currentRound?.id]);

  useEffect(() => {
    if (!roomState.questionResults || phase === "active") return;

    const correct = isAnswerCorrectFromReveal(roomState.questionResults.correct, answerValue);
    const backendScore = Number(roomState.myRank?.score);

    if (Number.isFinite(backendScore)) {
      if (backendScoreAppliedQuestionRef.current === currentRound.id) return;
      backendScoreAppliedQuestionRef.current = currentRound.id;
      const backendDelta = Math.max(0, backendScore - scoreBeforeQuestionRef.current);
      const backendSpeedBonus = correct
        ? Math.max(0, backendDelta - currentPoints)
        : 0;
      setLastAwardedPoints(backendDelta);
      setSubmittedSpeedBonus(Math.round(backendSpeedBonus));
      setTotalScore(backendScore);
      setStreakCount(correct ? (count) => count + 1 : 0);
      return;
    }

    if (awardedQuestionRef.current === currentRound.id) return;
    awardedQuestionRef.current = currentRound.id;
    const points = correct && hasAnswerResponse(currentRound, answerValue)
      ? currentPoints + submittedSpeedBonus
      : 0;

    setLastAwardedPoints(points);
    if (correct) {
      setTotalScore((score) => Number.isFinite(backendScore) ? backendScore : score + points);
      setStreakCount((count) => count + 1);
    } else {
      if (Number.isFinite(backendScore)) {
        setTotalScore(backendScore);
      }
      setStreakCount(0);
    }
  }, [
    answerValue,
    currentRound,
    currentRound.id,
    currentPoints,
    phase,
    roomState.myRank?.score,
    roomState.questionResults,
    submittedSpeedBonus,
    totalScore,
  ]);

  return (
    <ScreenShell
      eyebrow={isLobbyPhase ? "Real-time Participant Flow" : ""}
      title={isLobbyPhase ? assessment.name || "Untitled" : ""}
      description={isLobbyPhase ? assessment.description ?? "" : ""}
      variant={embedded ? "panel" : "page"}
      aside={null}
    >
      <div className="flex min-h-[32rem] flex-col sm:min-h-[34rem] lg:h-full lg:min-h-0">
        {phase === "lobby" ? (
          <div className="flex flex-1 items-start py-2 lg:items-center">
            <JoinLobby
              requiresIdentity={requiresIdentity}
              displayName={displayName}
              onDisplayNameChange={setDisplayName}
              email={email}
              onEmailChange={setEmail}
              onJoin={joinLobby}
              eventName={realtimeEvents.joinRoom}
            />
          </div>
        ) : null}

        {phase === "waiting" ? (
          <JoinWaitingState
            title="Waiting for host to start..."
            description="The first question opens when the host starts the round."
          />
        ) : null}

        {phase === "active" ? (
          <div className="mx-auto flex w-full max-w-5xl flex-1 flex-col py-2 sm:py-4 lg:justify-center">
            <div className="rt-card-pop overflow-hidden rounded-[30px] border border-[#1C5C45]/15 bg-white shadow-[0_24px_70px_rgba(27,67,50,0.10)]">
              <div className="border-b border-border/60 bg-[linear-gradient(135deg,#16352A_0%,#23513D_58%,#2D6A4F_100%)] p-5 text-white sm:p-6">
                <div className="flex flex-wrap items-center justify-between gap-3">
                  <div className="inline-flex items-center gap-2 rounded-full bg-white/10 px-3 py-1 text-xs font-semibold uppercase tracking-[0.18em] text-white/75">
                    <Radio className="h-4 w-4 text-[#95D5B2]" />
                    Live question
                  </div>
                  <div className="inline-flex items-center gap-2 rounded-full border border-white/15 bg-white/10 px-3 py-1 text-xs font-semibold text-white/85">
                    Question {questionNumber} of {totalQuestions}
                  </div>
                </div>

                <div className="mt-5 flex flex-col gap-4 lg:flex-row lg:items-end lg:justify-between">
                  <h2 className="max-w-3xl text-2xl font-bold leading-tight tracking-tight sm:text-3xl">
                    {currentRound.question || (currentRound as any).questionText}
                  </h2>
                  <div
                    className={`shrink-0 rounded-3xl border border-white/15 bg-white/10 px-5 py-4 text-right backdrop-blur ${
                      timerSeconds <= 5 ? "rt-timer-critical" : ""
                    }`}
                  >
                    <div className="flex items-center justify-end gap-2 text-white/65">
                      <Clock3 className="h-4 w-4" />
                      <span className="text-xs font-semibold uppercase tracking-[0.16em]">
                        Time left
                      </span>
                    </div>
                    <p className="mt-1 text-4xl font-black">{timerSeconds}s</p>
                  </div>
                </div>

                <div className="rt-progress-shimmer mt-5 h-2.5 rounded-full bg-white/12">
                  <div
                    className={`h-full rounded-full transition ${
                      timerSeconds <= 5
                        ? "bg-[linear-gradient(90deg,#FF6B6F_0%,#F94144_100%)]"
                        : "bg-[linear-gradient(90deg,#FFD166_0%,#95D5B2_100%)]"
                    }`}
                    style={{ width: `${timerProgressPercent}%` }}
                  />
                </div>
              </div>

              <div className="bg-[linear-gradient(180deg,#FFFEF8_0%,#F7F5F0_100%)] p-4 sm:p-6">
                <div className="w-full" data-flow-event={realtimeEvents.submitAnswer}>
                  <QuestionRenderer
                    question={currentRound}
                    value={answerValue}
                    onChange={selectAnswer}
                    disabled={submitted || hasTimedOut}
                  />
                </div>
              </div>
            </div>

            <div className="mx-auto mt-6 w-full max-w-md">
              {submitted ? (
                <div className="flex items-center justify-center gap-2 rounded-2xl bg-[#113023] px-6 py-4 text-center text-base font-bold text-white shadow-[0_18px_40px_rgba(17,48,35,0.18)]">
                  <CheckCircle2 className="h-5 w-5 text-emerald-300" />
                  Answer submitted! Waiting for results…
                </div>
              ) : hasTimedOut ? (
                <div className="flex items-center justify-center gap-2 rounded-2xl border border-[#FFD166]/60 bg-[#FFF6CC] px-6 py-4 text-center text-base font-bold text-[#113023] shadow-sm">
                  <Clock3 className="h-5 w-5" />
                  Time is up. Waiting for results…
                </div>
              ) : (
                <button
                  type="button"
                  onClick={handleSubmit}
                  disabled={!hasAnswerResponse(currentRound, answerValue)}
                  className="w-full rounded-2xl bg-gradient-to-r from-[#FFD166] to-[#F9C74F] px-6 py-4 text-base font-bold text-[#113023] shadow-lg transition-all hover:scale-[1.02] hover:shadow-xl disabled:cursor-not-allowed disabled:opacity-40 disabled:hover:scale-100"
                >
                  Submit Answer
                </button>
              )}
            </div>
          </div>
        ) : null}

        {roomState.questionResults && phase !== "active" ? (
          <JoinResult
            currentRound={currentRound}
            answerValue={answerValue}
            isCorrect={revealedCorrect}
            lastPoints={Number.isFinite(lastAwardedPoints) ? lastAwardedPoints : 0}
            totalScore={Number.isFinite(totalScore) ? totalScore : 0}
            speedBonus={submittedSpeedBonus}
            isLastQuestion={questionIndex === rounds.length - 1}
          />
        ) : null}

        {phase === "results" ? (
          <JoinFinal
            displayName={displayName}
            totalScore={totalScore}
            rank="#4"
            streakCount={streakCount}
          />
        ) : null}
      </div>
    </ScreenShell>
  );
}

function getRealtimeSpeedBonus(questionPoints: number, timerSeconds: number): number {
  if (!Number.isFinite(questionPoints) || questionPoints <= 0) return 0;
  const timeRatio = Math.max(0, Math.min(1, timerSeconds / QUESTION_DURATION_SECONDS));
  return Math.round(questionPoints * SPEED_BONUS_RATIO * timeRatio);
}

function parseCorrectAnswer(correct: unknown): unknown {
  if (typeof correct !== "string") return correct;
  try {
    return JSON.parse(correct);
  } catch {
    return correct;
  }
}

function isAnswerCorrectFromReveal(
  correct: unknown,
  answerValue: QuestionRendererValue,
): boolean {
  if (!hasAnswerResponse({ options: [], type: "SINGLE_CHOICE" } as any, answerValue)) {
    return false;
  }

  const parsed = parseCorrectAnswer(correct) as any;
  if (Array.isArray(answerValue)) {
    const correctIds = Array.isArray(parsed?.optionIds)
      ? parsed.optionIds
      : Array.isArray(parsed)
        ? parsed
        : [];
    return (
      answerValue.length === correctIds.length &&
      answerValue.every((id) => correctIds.includes(id))
    );
  }

  if (typeof answerValue === "boolean") {
    return parsed?.value === answerValue || String(parsed) === String(answerValue);
  }

  if (typeof answerValue === "string") {
    return parsed?.optionId === answerValue || String(parsed) === answerValue;
  }

  return false;
}

"use client";

import Avatar from "boring-avatars";
import Link from "next/link";
import { useEffect, useMemo, useRef, useState } from "react";
import {
  ArrowLeft,
  ArrowRight,
  CheckCircle2,
  Clock3,
  Copy,
  Crown,
  PlayCircle,
  QrCode,
  Radio,
  Trophy,
  Volume2,
  VolumeX,
} from "lucide-react";
import { QRCodeSVG } from "qrcode.react";
import type {
  AssessmentCatalogItem,
  AssessmentDetailQuestionItem,
} from "@/src/types";
import { QuestionRenderer } from "../renderers/QuestionRenderer";
import { ScreenShell } from "./SessionShared";
import { getAvatarColors, getAvatarVariant } from '@/src/lib/session/avatar.utils';
import { useRealtimeAudio } from '@/src/lib/session/realtime.effects';
import { realtimeEvents } from '@/src/lib/session/realtime.events';
import type { HostPhase } from '@/src/types/session.types';
import {
  buildDistribution,
  buildLeaderboard,
  buildParticipantRoster,
  buildQuestionRounds,
  resolveLeaderboardRound,
} from '@/src/lib/session/session.utils';
import { Button } from "@/src/components/ui/ui/button";
import { useRealtimeSession, type RealtimeSessionReturn } from "@/src/hooks/use-realtime-session";
import { RoomRole } from "@/src/types/runtime.types";
import { startRealtimeSessionHost } from "@/src/lib/actions/runtime.actions";
import { toast } from "sonner";

const QUESTION_DURATION_SECONDS = 30;

export function PresentRealTimeScreen({
  assessment,
  questions,
  embedded,
  session: externalSession,
  previewParticipants = [],
}: {
  assessment: AssessmentCatalogItem;
  questions: AssessmentDetailQuestionItem[];
  embedded?: boolean;
  session?: RealtimeSessionReturn;
  previewParticipants?: Array<{ id: string; name: string }>;
}) {
  const internalSession = useRealtimeSession({ enabled: !externalSession });
  const activeSession = externalSession || internalSession;
  const rounds = useMemo(() => buildQuestionRounds(questions), [questions]);
  const [copied, setCopied] = useState(false);
  const [questionIndex, setQuestionIndex] = useState(0);
  const [timerSeconds, setTimerSeconds] = useState(0);
  const [origin, setOrigin] = useState("");
  const previousTimerRef = useRef(timerSeconds);
  const autoRevealQuestionRef = useRef<string | null>(null);
  const { soundEnabled, setSoundEnabled, prime, playTone } = useRealtimeAudio();

  const { isConnected, roomState, joinRoom, emitStartQuestion, emitRevealAnswers } = activeSession;

  const phase = roomState.phase === "active" ? "reveal" : roomState.phase === "results" ? "winner" : roomState.phase as HostPhase;
  const previousPhaseRef = useRef<HostPhase>(phase);

  const participants = useMemo(() => buildParticipantRoster(), []);
  const initialLeaderboard = useMemo(() => buildLeaderboard(), []);

  const activeParticipants = roomState.participants.length > 0 ? roomState.participants : previewParticipants;
  const responseCount = roomState.questionResults ? (roomState.questionResults.totalAnswered || 0) : 0;

  const leaderboard = roomState.leaderboard || [];
  const displayLeaderboard = [
    ...leaderboard,
    ...activeParticipants
      .filter((participant: any) =>
        !leaderboard.some((entry: any) => entry.id === participant.id),
      )
      .map((participant: any) => ({
        id: participant.id,
        name: participant.name || "Anonymous",
        score: 0,
        rank: 0,
        previousRank: 0,
        streak: 0,
        lastGain: 0,
      })),
  ].map((entry: any, index: number) => ({
    ...entry,
    rank: entry.rank || index + 1,
    previousRank: entry.previousRank || entry.rank || index + 1,
  }));
  const hasParticipants = activeParticipants.length > 0;

  // When used standalone (no external session), auto-join as host
  const hostJoinedRef = useRef(false);
  useEffect(() => {
    if (externalSession || !isConnected || hostJoinedRef.current) return;
    async function initHost() {
      const res = await startRealtimeSessionHost(assessment.id);
      if (res.success) {
        joinRoom(assessment.id, RoomRole.HOST);
        hostJoinedRef.current = true;
      } else {
        toast.error("Failed to initialize host session on backend");
      }
    }
    initHost();
  }, [externalSession, assessment.id, joinRoom, isConnected]);

  const currentRound = rounds[questionIndex];
  const participantPath = `/assessments/${assessment.id}/enter-real-time-assessment`;
  const participantUrl = origin ? `${origin}${participantPath}` : participantPath;
  const responseDistribution = useMemo(
    () => {
      // If we have actual results from backend, map them
      if (roomState.questionResults) {
        // Map backend results to distribution, for now fallback to mock
        return buildDistribution(currentRound.options, responseCount, currentRound.correctOptionId);
      }
      return buildDistribution(currentRound.options, responseCount, currentRound.correctOptionId);
    },
    [currentRound, responseCount, roomState.questionResults],
  );
  const isLobbyPhase = phase === "lobby";

  useEffect(() => {
    const frameId = window.requestAnimationFrame(() => {
      setOrigin(window.location.origin);
    });

    return () => window.cancelAnimationFrame(frameId);
  }, []);


  useEffect(() => {
    if (phase !== "reveal" || !roomState.endTime) return;

    const tick = () => {
      const remaining = Math.max(0, Math.floor((new Date(roomState.endTime!).getTime() - Date.now()) / 1000));
      setTimerSeconds(remaining);
    };

    tick();
    const interval = setInterval(tick, 1000);
    return () => clearInterval(interval);
  }, [phase, roomState.endTime]);

  useEffect(() => {
    if (
      phase !== "reveal" ||
      !roomState.endTime ||
      !roomState.currentQuestion?.id
    ) {
      return;
    }

    const delay = Math.max(
      0,
      new Date(roomState.endTime).getTime() - Date.now() + 100,
    );
    const timeoutId = window.setTimeout(() => {
      if (autoRevealQuestionRef.current === roomState.currentQuestion?.id) {
        return;
      }
      autoRevealQuestionRef.current = roomState.currentQuestion.id;
      emitRevealAnswers(assessment.id);
    }, delay);

    return () => window.clearTimeout(timeoutId);
  }, [
    assessment.id,
    emitRevealAnswers,
    phase,
    roomState.currentQuestion?.id,
    roomState.endTime,
  ]);

  useEffect(() => {
    if (
      phase !== "reveal" ||
      !roomState.endTime ||
      !roomState.currentQuestion?.id
    ) {
      return;
    }
    const remainingMs = new Date(roomState.endTime).getTime() - Date.now();
    if (remainingMs > 0) return;
    if (autoRevealQuestionRef.current === roomState.currentQuestion.id) return;

    autoRevealQuestionRef.current = roomState.currentQuestion.id;
    emitRevealAnswers(assessment.id);
  }, [
    assessment.id,
    emitRevealAnswers,
    phase,
    roomState.currentQuestion?.id,
    roomState.endTime,
    timerSeconds,
  ]);


  useEffect(() => {
    if (previousPhaseRef.current !== phase) {
      if (phase === "reveal") {
        void playTone("reveal");
      } else if (phase === "correct") {
        void playTone("success");
      } else if (phase === "leaderboard") {
        void playTone("leaderboard");
      }
    }

    previousPhaseRef.current = phase;
  }, [phase, playTone]);

  useEffect(() => {
    if (phase !== "reveal" || previousTimerRef.current === timerSeconds) {
      previousTimerRef.current = timerSeconds;
      return;
    }

    if (timerSeconds > 0) {
