                        ? "from-[#F9C74F] to-[#FFD166] text-primary"
                        : place === 2
                          ? "from-[#D9E6F2] to-[#F4F8FB] text-primary"
                          : "from-[#E8B179] to-[#F4CC9C] text-primary";

                    return (
                      <div
                        key={entry.id}
                        className={`flex flex-col items-center ${orderClassName}`}
                      >
                        <div className="mb-4 flex flex-col items-center text-center">
                          <div className="h-16 w-16 overflow-hidden rounded-3xl ring-2 ring-white/25 shadow-[0_20px_40px_rgba(0,0,0,0.18)]">
                            <Avatar
                              size={64}
                              name={`${entry.id}-${entry.name}`}
                              variant={getAvatarVariant(`${entry.id}-${entry.name}`)}
                              colors={getAvatarColors(`${entry.id}-${entry.name}`)}
                            />
                          </div>
                          <p className="mt-4 text-xs font-semibold uppercase tracking-[0.18em] text-white/60">
                            {place === 1 ? "Champion" : `Place ${place}`}
                          </p>
                          <p className="mt-2 text-xl font-bold">{entry.name}</p>
                          <p className="mt-1 text-sm font-semibold text-[#D8F3DC]">{entry.score} pts</p>
                        </div>

                        <div
                          className={`flex w-full max-w-[13rem] flex-col items-center justify-center rounded-t-[32px] bg-linear-to-t ${stepTone} ${stepHeight} shadow-[0_24px_50px_rgba(0,0,0,0.16)]`}
                        >
                          {place === 1 ? (
                            <Crown className="mb-3 h-8 w-8 text-primary" />
                          ) : null}
                          <p className="text-4xl font-black">{place}</p>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>

              <div className="flex flex-col justify-end">
                <div className="rounded-[30px] border border-white/10 bg-white/8 p-5 backdrop-blur-sm">
                  <p className="text-xs font-semibold uppercase tracking-[0.18em] text-white/60">
                    Session closed
                  </p>
                  <h2 className="mt-3 text-2xl font-bold">Back to assessment</h2>
                  <p className="mt-3 text-sm leading-6 text-white/70">
                    Return to the assessment detail page to review the setup or launch another session.
                  </p>

                  <Link
                    href={embedded ? `/assessments/${assessment.id}/preview` : `/assessments/${assessment.id}`}
                    className="mt-6 inline-flex w-full items-center justify-center gap-2 rounded-2xl bg-[linear-gradient(135deg,#F94144_0%,#FF6B6F_100%)] px-5 py-3 text-sm font-semibold text-white transition hover:scale-[1.01]"
                  >
                    <ArrowLeft className="h-4 w-4" />
                    Back to assessment
                  </Link>
                </div>
              </div>
            </div>
          </div>
        ) : null}
      </div>
    </ScreenShell>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { Eye } from "lucide-react";
import type {
  AssessmentDetailQuestionItem,
  AssessmentDetailRecord,
} from "@/src/types";
import { BackButton } from "@/src/components/ui/navigation/BackButton";
import type { QuestionRendererValue } from "../renderers/types";
import {
  ProcessingAnswersCard,
  QuestionOptionButton,
  ScreenShell,
} from "./SessionShared";
import { SelfPacedConfirm } from "./self-paced/SelfPacedConfirm";
import { SelfPacedEntry } from "./self-paced/SelfPacedEntry";
import { SelfPacedQuiz } from "./self-paced/SelfPacedQuiz";
import { SelfPacedResult } from "./self-paced/SelfPacedResult";
import { RealTimeSimulator } from "./RealTimeSimulator";
import {
  buildQuestionRounds,
  formatDurationClock,
  getResultReleaseMode,
  isCorrectAnswerResponse,
  calculateQuestionScore,
  requiresParticipantIdentity,
  shuffleArray,
} from '@/src/lib/session/session.utils';

export function PreviewScreen({
  assessment,
  questions,
  previewMode,
  backHref,
}: {
  assessment: AssessmentDetailRecord;
  questions: AssessmentDetailQuestionItem[];
  previewMode: "SELF_PACED" | "REAL_TIME";
  backHref: string;
}) {
  const rounds = useMemo(() => {
    let qs = [...questions];
    if (assessment.settings?.isShuffle) {
      qs = shuffleArray(qs, assessment.id);
    }
    return buildQuestionRounds(qs, assessment.settings?.isShuffle ?? false);
  }, [questions, assessment.id, assessment.settings?.isShuffle]);
  const isSelfPacedPreview = previewMode === "SELF_PACED";
  const resultMode = getResultReleaseMode(assessment.settings?.showResults || "AFTER_SUBMISSION");
  const showCorrectAnswers = assessment.settings?.allowReview ?? false;
  const allowShareAnswerSheet = false;
  const requiresEntry = assessment.settings?.participantIdentity !== "ANONYMOUS";
  const requiresIdentity = requiresParticipantIdentity(assessment.settings?.participantIdentity || "EXTERNAL");
  const totalTimerSeconds = Math.max(0, (assessment.settings?.timeLimit ?? 0) * 60);
  const [displayName, setDisplayName] = useState(isSelfPacedPreview ? "Creator Preview" : "");
  const [email, setEmail] = useState(isSelfPacedPreview ? "preview@example.com" : "");
  const [step, setStep] = useState<"entry" | "quiz" | "confirm" | "processing" | "end">(
    requiresEntry ? "entry" : "quiz",
  );
  const [questionIndex, setQuestionIndex] = useState(0);
  const [remainingSeconds, setRemainingSeconds] = useState(totalTimerSeconds);
  const [answers, setAnswers] = useState<Record<string, QuestionRendererValue>>({});
  const currentQuestion = rounds[questionIndex];
  const confirmationItems = rounds.map((question) => ({
    question,
    answerValue: answers[question.id] ?? null,
  }));
  const scoreSummary = useMemo(() => {
    const totalPoints = rounds.reduce((sum, question) => sum + question.points, 0);
    const earnedPoints = rounds.reduce((sum, question) => {
      return sum + calculateQuestionScore(question, answers[question.id] ?? null);
    }, 0);
    const percent = totalPoints > 0 ? Math.round((earnedPoints / totalPoints) * 100) : 0;

    const sortedGradeLabels = [...(assessment.settings?.gradeLabels || [])].sort(
      (a, b) => b.minPercent - a.minPercent
    );

    const grade =
      sortedGradeLabels.find((band) => percent >= band.minPercent)?.grade ??
      sortedGradeLabels.at(-1)?.grade ??
      "N/A";

    return {
      earnedPoints,
      totalPoints,
      grade,
      passed: percent >= (assessment.settings?.passMark ?? 0),
    };
  }, [answers, assessment.settings?.gradeLabels, assessment.settings?.passMark, rounds]);

  useEffect(() => {
    if (step !== "processing") {
      return;
    }

    const timeoutId = window.setTimeout(() => {
      setStep("end");
    }, 1600);

    return () => window.clearTimeout(timeoutId);
  }, [step]);

  useEffect(() => {
    if (step !== "quiz" || totalTimerSeconds <= 0 || remainingSeconds <= 0) {
      return;
    }

    const timeoutId = window.setTimeout(() => {
      setRemainingSeconds((currentSeconds) => Math.max(0, currentSeconds - 1));
    }, 1000);

    return () => window.clearTimeout(timeoutId);
  }, [remainingSeconds, step, totalTimerSeconds]);

  function handleSelectAnswer(value: QuestionRendererValue) {
    setAnswers((currentAnswers) => ({
      ...currentAnswers,
      [currentQuestion.id]: value,
    }));
  }

  return (
    <ScreenShell
      title={assessment.name ? `Preview: ${assessment.name}` : "Assessment Preview"}
      description="Preview Mode Active — Your answers will not be recorded."
      headerAction={
        <div className="flex items-center gap-3">
          {step === "end" && (
            <button
              type="button"
              onClick={() => {
                setStep(requiresEntry ? "entry" : "quiz");
                setQuestionIndex(0);
                setAnswers({});
                setRemainingSeconds(totalTimerSeconds);
              }}
              className="inline-flex h-9 items-center justify-center rounded-xl bg-primary/10 px-4 text-sm font-bold text-primary transition-all hover:bg-primary/20"
            >
              Restart Preview
            </button>
          )}
          <BackButton
            href={backHref}
            label="Exit Preview"
          />
        </div>
      }
    >
      {!isSelfPacedPreview ? (
        <RealTimeSimulator assessment={assessment} questions={questions} />
      ) : null}

      {isSelfPacedPreview ? (
        <div className="flex flex-1 min-h-0 flex-col">
          {step === "entry" ? (
            <SelfPacedEntry
              heading="Before you begin"
              description="This preview mirrors the participant entry experience. You can answer the full flow, but nothing is saved."
              timeLimitMinutes={assessment.settings?.timeLimit ?? 0}
              requiresIdentity={requiresIdentity}
              displayName={displayName}
              onDisplayNameChange={setDisplayName}
              email={email}
              onEmailChange={setEmail}
              helperTitle="Participant identity"
              helperDescription={
                assessment.settings?.participantIdentity === "ANONYMOUS"
                  ? "Anonymous participants skip the display name form."
                  : "Internal participants can continue without entering a display name."
              }
              ctaLabel="Start preview quiz"
              onContinue={() => setStep("quiz")}
              backHref={backHref}
              backLabel="Back to assessment"
              showBackButton
            />
          ) : null}

          {step === "quiz" ? (
            <SelfPacedQuiz
              currentQuestion={currentQuestion}
              questionIndex={questionIndex}
              totalQuestions={rounds.length}
              timeLabel={formatDurationClock(remainingSeconds)}
              timerProgressPercent={(remainingSeconds / totalTimerSeconds) * 100}
              showTimer={totalTimerSeconds > 0}
              answerValue={answers[currentQuestion.id] ?? null}
              onChange={handleSelectAnswer}
              onPrevious={() => setQuestionIndex((currentIndex) => Math.max(0, currentIndex - 1))}
              onNext={() => {
                if (questionIndex === rounds.length - 1) {
                  setStep("confirm");
                  return;
                }
                setQuestionIndex((currentIndex) => currentIndex + 1);
              }}
              nextLabel={questionIndex === rounds.length - 1 ? "Review answers" : "Next question"}
              disablePrevious={questionIndex === 0}
            />
          ) : null}

          {step === "confirm" ? (
            <SelfPacedConfirm
              items={confirmationItems}
              allowGoingBack={assessment.settings?.allowReview ?? true}
              onBack={() => setStep("quiz")}
              onSubmit={() => setStep("processing")}
              submitLabel="Submit"
            />
          ) : null}

          {step === "processing" ? (
            <ProcessingAnswersCard
              title="Processing answer preview"
              description="This preview simulates the short evaluation state shown right after a participant submits the assessment."
            />
          ) : null}

          {step === "end" ? (
            <>
              <SelfPacedResult
                resultMode={resultMode}
                scoreSummary={scoreSummary}
                allowShareAnswerSheet={allowShareAnswerSheet}
                showCorrectAnswers={showCorrectAnswers}
                items={confirmationItems}
                answerSheetTitle="Answer sheet"
                answerSheetHeading="Preview every answer response"
              />
            </>
          ) : null}
        </div>
      ) : null}
    </ScreenShell>
  );
}

"use client";

import { useMemo, useEffect } from "react";
import { useRouter } from "next/navigation";
import type { AssessmentResultSheetPageData } from "@/src/types/assessment-results.types";
import type { AnswerEntry } from "@/src/types/answer-entry.types";
import { SelfPacedResult } from "./self-paced/SelfPacedResult";
import type { QuestionRound } from "@/src/types/session.types";
import { ScreenShell } from "./SessionShared";

function parseResponseValue(entry: AnswerEntry) {
  if (typeof entry.response === "string") {
    try {
      const parsed = JSON.parse(entry.response);
      if (typeof parsed === "number" && entry.questionSnapshot.typeId === "SINGLE_CHOICE") {
        return String(parsed);
      }
      return parsed;
    } catch {
      return entry.response;
    }
  }
  return entry.response;
}

export function PublicResultClient({ data }: { data: AssessmentResultSheetPageData }) {
  const router = useRouter();

  useEffect(() => {
    const hasPending = data.answerEntries.some((e) => e.gradingStatus === "PENDING");
    if (!hasPending) return;

    const interval = setInterval(() => {
      router.refresh();
    }, 5000);
    return () => clearInterval(interval);
  }, [data.answerEntries, router]);

  const scoreSummary = useMemo(() => {
    const totalPoints = data.assessment.settings?.passMark || 0; // The actual UI computes this from rounds. Let's just use what's on the sheet.
    return {
      earnedPoints: data.answerSheet.totalScore ?? 0,
      totalPoints: data.answerSheet.maxScore ?? 0,
      grade: data.answerSheet.grade ?? "N/A",
      passed: data.answerSheet.isPassed ?? false,
    };
  }, [data]);

  const items = useMemo(() => {
    return data.answerEntries.map((entry) => {
      const question: QuestionRound = {
        id: entry.questionId,
        type: entry.questionSnapshot.typeId as any,
        question: entry.questionSnapshot.questionText,
        options: Array.isArray(entry.questionSnapshot.options) ? entry.questionSnapshot.options : [],
        rawOptions: entry.questionSnapshot.options,
        correctAnswers: entry.questionSnapshot.correctAnswers,
        correctOptionId: (entry.questionSnapshot.correctAnswers as any)?.optionId,
        points: entry.questionSnapshot.points,
      } as unknown as QuestionRound;

      return {
        question,
        answerValue: parseResponseValue(entry),
      };
    });
  }, [data]);

  const resultMode = data.assessment.settings?.showResults === "AFTER_SUBMISSION" ? "immediate" : "manual";

  return (
    <ScreenShell
      eyebrow="Public Result"
      title={data.assessment.name || "Assessment"}
      description={data.assessment.description!}
      aside={null}
    >
      <div className="flex flex-1 min-h-0 flex-col">
        <SelfPacedResult
          resultMode={resultMode}
          scoreSummary={scoreSummary}
          allowShareAnswerSheet={false} // Don't allow sharing from the shared page itself
          showCorrectAnswers={data.assessment.settings?.allowReview ?? false}
          items={items}
          answerSheetTitle="Answer sheet"
          answerSheetHeading="Review every answer response"
        />
      </div>
    </ScreenShell>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import type {
  AssessmentDetailQuestionItem,
  AssessmentDetailRecord,
} from "@/src/types";
import type { QuestionRendererValue } from "../renderers/types";
import {
  ProcessingAnswersCard,
  ScreenShell,
} from "./SessionShared";
import { SelfPacedConfirm } from "./self-paced/SelfPacedConfirm";
import { SelfPacedEntry } from "./self-paced/SelfPacedEntry";
import { SelfPacedQuiz } from "./self-paced/SelfPacedQuiz";
import { SelfPacedResult } from "./self-paced/SelfPacedResult";
import {
  buildQuestionRounds,
  formatDurationClock,
  getResultReleaseMode,
  isCorrectAnswerResponse,
  requiresParticipantIdentity,
} from '@/src/lib/session/session.utils';
import {
  startSelfPacedSession,
  saveAnswerIncremental,
  submitSelfPacedSession,
  getSessionResult,
} from "@/src/lib/actions/runtime.actions";
import { toast } from "sonner";

export function StartSelfPacedScreen({
  assessment,
  questions,
}: {
  assessment: AssessmentDetailRecord;
  questions: AssessmentDetailQuestionItem[];
}) {
  const rounds = useMemo(() => buildQuestionRounds(questions), [questions]);
  const requiresEntry = assessment.settings?.participantIdentity !== "ANONYMOUS";
  const requiresIdentity = requiresParticipantIdentity(assessment.settings?.participantIdentity || "EXTERNAL");
  const resultMode = getResultReleaseMode(assessment.settings?.showResults || "AFTER_SUBMISSION");
  const showCorrectAnswers = assessment.settings?.allowReview ?? false;
  const allowShareAnswerSheet = true;
  const totalTimerSeconds = Math.max(0, (assessment.settings?.timeLimit ?? 0) * 60);
  const [displayName, setDisplayName] = useState("");
  const [email, setEmail] = useState("");
  const [step, setStep] = useState<"entry" | "quiz" | "confirm" | "processing" | "end">(
    requiresEntry ? "entry" : "quiz",
  );
  const [questionIndex, setQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<Record<string, QuestionRendererValue>>({});
  const [remainingSeconds, setRemainingSeconds] = useState(totalTimerSeconds);
  const [sessionId, setSessionId] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [serverResult, setServerResult] = useState<any>(null);


  const currentQuestion = rounds[questionIndex];
  const confirmationItems = rounds.map((question) => {
    return {
      question,
      answerValue: answers[question.id] ?? null,
    };
  });

  const scoreSummary = useMemo(() => {
    const totalPoints = rounds.reduce((sum, question) => sum + question.points, 0);
    const earnedPoints = rounds.reduce((sum, question) => {
      return isCorrectAnswerResponse(question, answers[question.id] ?? null)
        ? sum + question.points
        : sum;
    }, 0);
    const percent = totalPoints > 0 ? Math.round((earnedPoints / totalPoints) * 100) : 0;
    const grade =
      assessment.settings?.gradeLabels?.find((band) => percent >= band.minPercent)?.grade ??
      assessment.settings?.gradeLabels?.at(-1)?.grade ??
      "N/A";

    return {
      earnedPoints,
      totalPoints,
      grade,
      passed: percent >= (assessment.settings?.passMark ?? 0),
    };
  }, [answers, assessment.settings?.gradeLabels, assessment.settings?.passMark, rounds]);

  const finalScoreSummary = serverResult?.session ? {
    earnedPoints: serverResult.session.pointsEarned ?? scoreSummary.earnedPoints,
    totalPoints: serverResult.session.pointsTotal ?? scoreSummary.totalPoints,
    grade: serverResult.session.grade ?? scoreSummary.grade,
    passed: serverResult.session.isPassed ?? scoreSummary.passed,
  } : scoreSummary;



    // Poll for real-time updates when on the end screen
  useEffect(() => {
    if (step !== "end" || !sessionId) return;
    const interval = setInterval(async () => {
      const res = await getSessionResult(sessionId);
      if (res.success) {
        setServerResult(res.data);
      }
    }, 5000);
    return () => clearInterval(interval);
  }, [step, sessionId]);

  useEffect(() => {
    if (step !== "quiz" || totalTimerSeconds <= 0 || remainingSeconds <= 0) {
      return;
    }

    const timeoutId = window.setTimeout(() => {
      setRemainingSeconds((currentSeconds) => Math.max(0, currentSeconds - 1));
    }, 1000);

    return () => window.clearTimeout(timeoutId);
  }, [remainingSeconds, step, totalTimerSeconds]);

  function handleSelectAnswer(value: QuestionRendererValue) {
    setAnswers((currentAnswers) => ({
      ...currentAnswers,
      [currentQuestion.id]: value,
    }));
  }

  async function handleAdvanceFromQuiz() {
    // Save answer incrementally
    if (sessionId && answers[currentQuestion.id] !== undefined) {
      await saveAnswerIncremental(sessionId, currentQuestion.id, answers[currentQuestion.id]);
    }

    if (questionIndex === rounds.length - 1) {
      setStep("confirm");
      return;
    }

    setQuestionIndex((currentIndex) => currentIndex + 1);
  }

  async function handleStartQuiz() {
    setIsSubmitting(true);
    let participantData = undefined;
    if (requiresIdentity && displayName.trim()) {
      participantData = { name: displayName, email: email || "" };
    }

    const res = await startSelfPacedSession(assessment.id, participantData);
    setIsSubmitting(false);

    if (res.success && res.data?.sessionId) {
      setSessionId(res.data.sessionId);
      setStep("quiz");
    } else {
      toast.error(res.message || "Failed to start session");
    }
  }

  async function handleSubmitSession() {
    if (!sessionId) return;

    // Save the last answer if changed and not saved yet (just to be safe)
    if (answers[currentQuestion.id] !== undefined) {
      await saveAnswerIncremental(sessionId, currentQuestion.id, answers[currentQuestion.id]);
    }

    setStep("processing");
    const startTime = Date.now();
    const submitRes = await submitSelfPacedSession(sessionId, assessment.id);
    if (!submitRes.success) {
      toast.error(submitRes.message || "Failed to submit session");
      setStep("confirm");
      return;
    }

    // Get the final result
    const resultRes = await getSessionResult(sessionId);
    if (resultRes.success) {
      setServerResult(resultRes.data);
    }

    // Ensure a minimum of 1.5s delay for the processing animation UX
    const elapsed = Date.now() - startTime;
    if (elapsed < 1500) {
      await new Promise(resolve => setTimeout(resolve, 1500 - elapsed));
    }

    setStep("end");
  }

  return (
    <ScreenShell
      eyebrow={step === "entry" ? "Self-paced Participant Flow" : ""}
      title={step === "entry" ? assessment.name || "Untitled" : ""}
      description={step === "entry" ? assessment.description! : ""}
      aside={null}
    >
      <div className="flex flex-1 min-h-0 flex-col">
        {step === "entry" ? (
          <SelfPacedEntry
            heading="Before you begin"
            timeLimitMinutes={assessment.settings?.timeLimit ?? 0}
            requiresIdentity={requiresIdentity}
            displayName={displayName}
            onDisplayNameChange={setDisplayName}
            email={email}
            onEmailChange={setEmail}
            helperTitle="Participant identity"
            helperDescription="Internal participants can continue without entering a display name."
            ctaLabel={isSubmitting ? "Starting..." : "Start quiz"}
            onContinue={handleStartQuiz}
          />
        ) : null}

        {step === "quiz" ? (
          <SelfPacedQuiz
            currentQuestion={currentQuestion}
            questionIndex={questionIndex}
            totalQuestions={rounds.length}
            timeLabel={formatDurationClock(remainingSeconds)}
            timerProgressPercent={(remainingSeconds / totalTimerSeconds) * 100}
            showTimer={totalTimerSeconds > 0}
            answerValue={answers[currentQuestion.id] ?? null}
            onChange={handleSelectAnswer}
            onPrevious={() => setQuestionIndex((currentIndex) => Math.max(0, currentIndex - 1))}
            onNext={handleAdvanceFromQuiz}
            nextLabel={questionIndex === rounds.length - 1 ? "Review answers" : "Next question"}
            disablePrevious={questionIndex === 0}
          />
        ) : null}

        {step === "confirm" ? (
          <SelfPacedConfirm
            items={confirmationItems}
            allowGoingBack={assessment.settings?.allowReview ?? true}
            onBack={() => setStep("quiz")}
            onSubmit={handleSubmitSession}
            submitLabel="Submit answers"
          />
        ) : null}

        {step === "processing" ? (
          <ProcessingAnswersCard
            title="Processing your answers"
            description="We are reviewing your answer responses and preparing a clean result sheet for you."
          />
        ) : null}

        {step === "end" ? (
          <SelfPacedResult
            shareUrl={`/public-results/${sessionId}`}
            resultMode={resultMode}
            scoreSummary={finalScoreSummary}
            allowShareAnswerSheet={allowShareAnswerSheet}
            showCorrectAnswers={showCorrectAnswers}
            items={confirmationItems}
            answerSheetTitle="Answer sheet"
            answerSheetHeading="Review every answer response"
          />
        ) : null}
      </div>
    </ScreenShell>
  );
}

import { ArrowRight, CheckCircle2 } from "lucide-react";
import type { QuestionRound } from '@/src/types/session.types';
import { Button } from "@/src/components/ui/ui/button";

export function HostCorrect({
  currentRound,
  responseDistribution,
  onNext,
}: {
  currentRound: QuestionRound;
  responseDistribution: { optionId: string; count: number }[];
  onNext: () => void;
}) {
  return (
    <div className="flex flex-col gap-4 lg:h-full lg:min-h-0">
      <div className="flex flex-wrap items-start justify-between gap-4">
        <div>
          <div className="inline-flex items-center gap-2 rounded-full bg-[linear-gradient(135deg,#43AA8B_0%,#7FE0C0_100%)] px-3 py-1 text-xs font-semibold text-white shadow-sm">
            <CheckCircle2 className="h-4 w-4" />
            Correct answer
          </div>
          <h2 className="mt-4 max-w-4xl text-2xl font-bold text-primary">{currentRound.question}</h2>
        </div>
        <Button
          type="button"
          onClick={onNext}
          className="inline-flex items-center justify-center gap-2 rounded-2xl bg-primary px-5 py-3 text-sm font-semibold text-white transition hover:opacity-90"
        >
          Next
          <ArrowRight className="h-4 w-4" />
        </Button>
      </div>

      <div className="min-h-0 flex-1 rounded-[30px] border border-border bg-white p-4 shadow-sm sm:p-5">
        <div className="grid h-full min-h-80 grid-cols-4 items-stretch gap-3 rounded-3xl bg-[linear-gradient(180deg,#F8FBF7_0%,#EEF5F1_100%)] p-4 sm:gap-4 sm:p-5">
          {currentRound.options.map((option: any, index: number) => {
            const distribution = responseDistribution.find((item) => item.optionId === option.id)?.count ?? 0;
            const maxCount = Math.max(...responseDistribution.map((item) => item.count), 1);
            const heightPercent = maxCount > 0 ? Math.max(18, Math.round((distribution / maxCount) * 100)) : 18;
            const isCorrect = option.id === currentRound.correctOptionId;
            const paletteClassName = [
              "from-[#F94144] to-[#FF6B6F]",
              "from-[#277DA1] to-[#4CC9F0]",
              "from-[#F9C74F] to-[#FFD166]",
              "from-[#43AA8B] to-[#7FE0C0]",
            ][index % 4];

            return (
              <div key={option.id} className="flex h-full min-w-0 flex-col items-center gap-3">
                <div className="shrink-0 text-lg font-bold text-primary">{distribution}</div>
                <div className="flex min-h-0 flex-1 w-full items-end justify-center">
                  <div
                    className={`rt-bar-grow flex w-full max-w-32 flex-col justify-end rounded-t-3xl bg-linear-to-t ${paletteClassName} px-3 py-4 text-center shadow-[0_16px_30px_rgba(27,67,50,0.12)] ${
                      isCorrect ? "ring-4 ring-[#D8F7EC]" : ""
                    }`}
                    style={{ height: `${heightPercent}%`, animationDelay: `${index * 90}ms` }}
                  >
                    {isCorrect ? (
                      <span className="mb-2 inline-flex self-center rounded-full bg-white/80 px-2 py-1 text-[10px] font-bold uppercase tracking-[0.18em] text-primary">
                        Correct
                      </span>
                    ) : null}
                    <span className={`text-sm font-black ${index === 2 ? "text-primary" : "text-white"}`}>
                      {option.label}
                    </span>
                  </div>
                </div>
                <p className="line-clamp-3 min-h-15 shrink-0 text-center text-sm font-semibold leading-5 text-primary">
                  {option.text}
                </p>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

