function formatDate(dateString: string) {
  return new Intl.DateTimeFormat("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
  }).format(new Date(dateString));
}

function getVisibilityLabel(visibility: QuestionBank["visibility"]) {
  switch (visibility) {
    case "PUBLIC":
      return "Public";
    case "SHARED":
      return "Organization";
    default:
      return "Private";
  }
}

