import { useState, useEffect } from "react";
import type { QuestionBank } from "@/src/types/api";
import type { Topic } from "@/src/types/topic.types";
import type { QuestionFormData } from "@/src/types/question-form.types";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/src/components/ui/ui/card";
import { CheckCircle, Circle, Square, Type, AlignLeft, GripVertical, Check, Star, ChevronUp, ChevronDown } from "lucide-react";

function getOptionLabel(index: number) {
  return String.fromCharCode(65 + index);
}

export default function QuestionPreviewCard({
  banks,
  topics,
  formData,
  title = "Preview",
  description,
  showAnswers = false,
  hideMetadata = false,
}: {
  banks: QuestionBank[];
  topics: Topic[];
  formData: QuestionFormData;
  title?: string;
  description?: string;
  showAnswers?: boolean;
  hideMetadata?: boolean;
}) {
  const ownerTopic = topics.find((topic) => topic.id === formData.ownerTopicId);

  const { questionType, options, correctAnswers } = formData;

  const [orderingState, setOrderingState] = useState<any[]>([]);
  const [matchingState, setMatchingState] = useState<Record<string, string>>({});
  const [fillInBlankState, setFillInBlankState] = useState<Record<number, string>>({});

  useEffect(() => {
    if (questionType === "Ordering" && !showAnswers) {
      const opts = Array.isArray(options) ? [...options] : [];
      setOrderingState(opts.sort(() => Math.random() - 0.5));
    }
  }, [options, questionType, showAnswers]);

  const moveOrderingItem = (index: number, direction: 'up' | 'down') => {
    const newOrder = [...orderingState];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= newOrder.length) return;
    const temp = newOrder[index];
    newOrder[index] = newOrder[targetIndex];
    newOrder[targetIndex] = temp;
    setOrderingState(newOrder);
  };

  const renderPreview = () => {
    switch (questionType) {
      case "Single Choice":
      case "Multiple Choices": {
        const isMultiple = questionType === "Multiple Choices";
        const correctIds = isMultiple 
          ? (correctAnswers?.optionIds || []) 
          : (correctAnswers?.optionId ? [correctAnswers.optionId] : []);
        const opts = Array.isArray(options) ? options : [];

        return (
          <div className="space-y-3">
            {opts.map((opt: any, index: number) => {
              const isCorrect = showAnswers && correctIds.includes(opt.id);
              return (
                <div
                  key={opt.id || index}
                  className={`flex items-center gap-3 rounded-xl border-2 px-4 py-3 transition-colors ${
                    isCorrect ? "border-yellow-500 bg-yellow-50" : "border-slate-100 bg-slate-50"
                  }`}
                >
                  <div
                    className={`flex h-5 w-5 shrink-0 items-center justify-center rounded text-sm ${
                      isCorrect ? "text-yellow-600" : "text-slate-400"
                    }`}
                  >
                    {isMultiple ? <Square className="h-5 w-5" /> : <Circle className="h-5 w-5" />}
                  </div>
                  <span className={`text-sm flex-1 ${isCorrect ? "text-yellow-800 font-medium" : "text-slate-700"}`}>
                    {opt.text || `Option ${getOptionLabel(index)}`}
                  </span>
                  {isCorrect && (
                    <span className="inline-flex items-center gap-1 rounded-full bg-yellow-100 px-3 py-1 text-[10px] font-bold text-yellow-700 uppercase tracking-wider">
                      <CheckCircle className="h-3 w-3" />
                      Correct
                    </span>
                  )}
                </div>
              );
            })}
          </div>
        );
      }

      case "True/False": {
        const isTrue = correctAnswers?.value === true;
        const trueLabel = options?.trueLabel || "True";
        const falseLabel = options?.falseLabel || "False";

        return (
          <div className="grid grid-cols-2 gap-4">
            {[trueLabel, falseLabel].map((label, idx) => {
              const isOptionTrue = idx === 0;
              const isCorrect = showAnswers && ((isOptionTrue && isTrue) || (!isOptionTrue && !isTrue));
              return (
                <div
                  key={label}
                  className={`flex flex-col items-center justify-center p-4 rounded-xl border-2 transition-colors ${
                    isCorrect ? "border-emerald-500 bg-emerald-50 text-emerald-700" : "border-slate-100 bg-slate-50 text-slate-500"
                  }`}
                >
                  <Circle className={`h-6 w-6 mb-2 ${isCorrect ? "text-emerald-500" : "text-slate-300"}`} />
                  <span className="text-sm font-bold">{label}</span>
                </div>
              );
            })}
          </div>
        );
      }

      case "Ordering": {
        const sequenceIds = correctAnswers?.sequence || [];
        const opts = Array.isArray(options) ? options : [];

        // In participant mode, we would randomize options. In preview with answers, we show the correct sequence.
        const itemsToRender = showAnswers && sequenceIds.length > 0
          ? sequenceIds.map((id:string) => opts.find((o:any) => o.id === id) || { text: id })
          : opts;

        return (
          <div className="space-y-2">
            {itemsToRender.map((opt: any, index: number) => (
              <div
                key={index}
                className={`flex items-center gap-3 rounded-xl border-2 px-4 py-1 text-sm font-medium ${
                  showAnswers ? "border-purple-300 bg-purple-50 text-purple-800" : "border-slate-100 bg-slate-50 text-slate-700"
                }`}
              >
                {showAnswers ? (
                  <span className="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-purple-500 text-[10px] font-bold text-white shadow-sm">
                    {index + 1}
                  </span>
                ) : (
                  <div className="flex flex-col gap-1 shrink-0">
                    <button onClick={() => moveOrderingItem(index, 'up')} disabled={index === 0} className="text-slate-400 hover:text-purple-600 disabled:opacity-30 p-1.5 sm:p-2 transition-colors rounded-md hover:bg-purple-50">
                      <ChevronUp className="h-4 w-4 sm:h-5 sm:w-5" />
                    </button>
                    <button onClick={() => moveOrderingItem(index, 'down')} disabled={index === itemsToRender.length - 1} className="text-slate-400 hover:text-purple-600 disabled:opacity-30 p-1.5 sm:p-2 transition-colors rounded-md hover:bg-purple-50">
                      <ChevronDown className="h-4 w-4 sm:h-5 sm:w-5" />
                    </button>
                  </div>
                )}
                <span>{opt.text || `Item ${index + 1}`}</span>
              </div>
            ))}
          </div>
        );
      }

      case "Matching": {
        const leftSide = options?.leftSide || [];
        const rightSide = options?.rightSide || [];
        const pairs = correctAnswers?.pairs || [];

        return (
          <div className="flex flex-col gap-3">
            {pairs.map((pair: any, index: number) => {
              const leftText = leftSide.find((l: any) => l.id === pair.leftId)?.text || `Left ${index + 1}`;
              const rightText = rightSide.find((r: any) => r.id === pair.rightId)?.text || `Right ${index + 1}`;

              // If not showing answers, offset the right text
              const displayRightText = showAnswers || pairs.length <= 1 
                ? rightText 
                : (rightSide.find((r: any) => r.id === pairs[(index + 1) % pairs.length]?.rightId)?.text || `Right ${(index + 1) % pairs.length + 1}`);

              return (
                <div key={index} className="flex flex-col sm:flex-row items-stretch sm:items-center gap-3">
                  <div className="flex-1 rounded-xl border border-slate-200 bg-slate-50 px-4 py-3 text-sm text-slate-700 text-center font-medium">
                    {leftText}
                  </div>
                  <div className="hidden sm:flex text-slate-300 shrink-0">
                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                      <path d="M5 12h14"></path>
                      <path d="m12 5 7 7-7 7"></path>
                    </svg>
                  </div>
                  {showAnswers ? (
                    <div className={`flex-1 rounded-xl border-2 px-4 py-3 text-sm font-medium text-center relative flex items-center justify-center border-orange-400 bg-orange-50 text-orange-800`}>
                      <span>{displayRightText}</span>
                      <CheckCircle className="absolute right-3 h-4 w-4 text-orange-500" />
                    </div>
                  ) : (
                    <div className="flex-1 relative">
                      <select
                        value={matchingState[pair.leftId] || ""}
                        onChange={(e) => setMatchingState(prev => ({ ...prev, [pair.leftId]: e.target.value }))}
                        className="w-full appearance-none rounded-xl border-2 border-slate-200 bg-white pl-4 pr-10 py-3 text-sm font-medium text-slate-700 focus:outline-none focus:border-orange-400 focus:ring-2 focus:ring-orange-500/20 transition-all shadow-sm cursor-pointer"
                      >
                        <option value="" disabled>Select match...</option>
                        {rightSide.map((r: any, rIndex: number) => (
                          <option key={r.id} value={r.id}>{r.text || `Right ${rIndex + 1}`}</option>
                        ))}
                      </select>
                      <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400 pointer-events-none" />
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        );
      }

      case "Fill in the Blank": {
        const template = options?.template || "Your template will appear here...";
        const answers = correctAnswers?.answers || [];

        const renderFillInTheBlankTemplate = () => {
          const parts = template.split(/(\[blank_\d+\])/g);
          return (
            <div className="leading-loose text-slate-800 text-base">
              {parts.map((part: string, index: number) => {
                const match = part.match(/\[blank_(\d+)\]/);
                if (match) {
                  const blankIdx = parseInt(match[1], 10) - 1;
                  if (showAnswers) {
                     return <span key={index} className="bg-pink-100 text-pink-700 font-bold px-2 py-1 mx-1 rounded shadow-sm">{part}</span>;
                  }
                  return (
                    <input 
                      key={index}
                      className="mx-1 inline-block w-32 border-b-2 border-slate-300 bg-white px-2 py-1 text-center text-sm font-bold text-slate-700 placeholder:text-slate-300 placeholder:font-normal focus:border-pink-500 focus:outline-none focus:ring-0 transition-colors shadow-sm rounded-t-md"
                      placeholder={`Blank ${blankIdx + 1}`}
                      value={fillInBlankState[blankIdx] || ""}
                      onChange={(e) => setFillInBlankState(prev => ({...prev, [blankIdx]: e.target.value}))}
                    />
                  );
                }
                return <span key={index}>{part}</span>;
              })}
            </div>
          );
        };

        return (
          <div className="space-y-4">
            <div className="p-5 rounded-xl bg-slate-50 border border-slate-200">
              {renderFillInTheBlankTemplate()}
            </div>

            {showAnswers && answers.length > 0 && (
              <div className="rounded-xl border border-pink-200 bg-pink-50/50 p-4">
                <div className="mb-3 text-[10px] font-bold uppercase tracking-wider text-pink-600">Expected Answers</div>
                <div className="flex flex-col gap-2">
                  {answers.map((ansGroup: string[], idx: number) => (
                    <div key={idx} className="flex items-start gap-2">
                      <span className="text-pink-600 font-bold text-xs mt-1 w-16">[blank_{idx + 1}]</span>
                      <div className="flex flex-wrap gap-1.5">
                        {ansGroup.map((ans, i) => (
                          <span key={i} className="bg-white border border-pink-200 text-pink-700 px-2.5 py-0.5 rounded shadow-sm text-xs font-medium">
                            {ans || "empty"}
                          </span>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        );
      }

      case "Short Answer":
      case "Essay": {
        const keywords = correctAnswers?.keyPointsExpected || [];
        const minWords = options?.minWords || 0;
        const maxWords = options?.maxWords || 0;

        return (
          <div className="space-y-4">
            <textarea 
              disabled 
              placeholder="Participant's answer will go here..." 
              rows={questionType === "Essay" ? 5 : 2}
              className="w-full rounded-xl border border-slate-200 bg-slate-50 p-4 text-sm text-slate-400 resize-none focus:outline-none"
            />

            {showAnswers && (
              <div className="rounded-xl border border-blue-200 bg-blue-50/50 p-4 space-y-4">
                <div className="flex gap-3 text-xs font-medium text-blue-800">
                  <div className="flex items-center gap-1 bg-white px-2 py-1 rounded shadow-sm">
                    <AlignLeft className="h-3 w-3 text-blue-400" /> Min: {minWords}
                  </div>
                  {maxWords > 0 && (
                    <div className="flex items-center gap-1 bg-white px-2 py-1 rounded shadow-sm">
                      <AlignLeft className="h-3 w-3 text-blue-400" /> Max: {maxWords}
                    </div>
                  )}
                </div>

                <div>
                  <div className="flex items-center gap-1.5 mb-2 text-[10px] font-bold uppercase tracking-wider text-blue-600">
                    <Type className="h-3 w-3" /> Expected Key Points
                  </div>
                  <div className="flex flex-wrap gap-1.5">
                    {keywords.length > 0 && keywords[0] !== "" ? (
                      keywords.map((kw: string, idx: number) => (
                        <span key={idx} className="bg-white border border-blue-200 text-blue-700 px-2 py-0.5 rounded text-xs shadow-sm font-medium">
                          {kw}
                        </span>
                      ))
                    ) : (
                      <span className="text-xs text-blue-700/50 italic">None specified</span>
                    )}
                  </div>
                </div>
              </div>
            )}
          </div>
        );
      }

      case "Rating Scale": {
        const max = options?.max || 5;
        const lowLabel = options?.lowLabel || "Low";
        const highLabel = options?.highLabel || "High";

        return (
          <div className="space-y-4 pt-2">
            <div className="flex flex-wrap justify-center gap-2 sm:gap-3">
              {Array.from({ length: max }).map((_, i) => (
                <Star 
                  key={i} 
                  className="h-8 w-8 sm:h-10 sm:w-10 text-slate-200 fill-slate-50 transition-colors hover:text-yellow-400 hover:fill-yellow-400 cursor-pointer" 
                  strokeWidth={1.5}
                />
              ))}
            </div>
            <div className="flex justify-between px-2 sm:px-4 text-[10px] sm:text-xs font-bold uppercase tracking-wider text-slate-500">
              <span className="text-center w-1/3 text-left">{lowLabel}</span>
              <span className="text-center w-1/3 text-right">{highLabel}</span>
            </div>
          </div>
        );
      }

      default:
        return (
          <div className="p-6 text-center text-sm text-slate-400 bg-slate-50 rounded-xl border border-slate-200 border-dashed">
            Preview is not available for this type yet.
          </div>
        );
    }
  };

  return (
    <Card className="shadow-sm border-slate-200 overflow-hidden bg-white relative">
      <CardHeader className="bg-slate-50 border-b border-slate-100 rounded-t-xl pb-4">
        <div className="flex items-center justify-between">
          <div>
            <CardTitle className="text-lg text-slate-800 flex items-center gap-2">
              <svg width="20" height="20" className="text-yellow-500" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M2 12h4l2-9 5 18 2-9h5"/></svg>
              {title}
            </CardTitle>
            {description ? <CardDescription className="mt-1">{description}</CardDescription> : null}
          </div>
        </div>
      </CardHeader>
      <CardContent className="space-y-6 pt-0">
        <div className="p-5 mt-6 rounded-2xl bg-white border border-indigo-100 shadow-sm">
          <div className="mb-4">
            <div className="flex items-start gap-2">
              <span className="text-sm font-black text-indigo-300 mt-0.5">Q.</span>
              <p className="flex-1 text-sm font-medium text-slate-800 leading-relaxed">
                {formData.questionText || <span className="text-slate-400 italic">Your question text will appear here...</span>}
              </p>
              {!hideMetadata && (
                <span className="shrink-0 inline-flex items-center px-2.5 py-1 rounded-md bg-slate-100 text-[10px] font-bold text-slate-500 uppercase tracking-wider mt-0.5">
                  {formData.points} {Number(formData.points) === 1 ? "pt" : "pts"}
                </span>
              )}
            </div>
          </div>

          <div className="mt-6 pt-6 border-t border-slate-100">
            {renderPreview()}
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

import type { ReactNode } from "react";
import type { QuestionFormData } from "@/src/types/question-form.types";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/src/components/ui/ui/card";
import { Check, GripVertical, Plus, X, Type, ListOrdered, Link as LinkIcon, Edit3, MessageSquare, Star, FileQuestion, ChevronUp, ChevronDown } from "lucide-react";
import { Label } from "@/src/components/ui/ui/label";
import { Button } from "@/src/components/ui/ui/button";
import { Select } from "@/src/components/ui/ui/select";
import { Input } from "@/src/components/ui/ui/input";
import { Textarea } from "@/src/components/ui/ui/textarea";

function getOptionLabel(index: number) {
  return String.fromCharCode(65 + index);
}

export default function QuestionTypeSettingsCard({
  formData,
  onChange,
  title = "Question Settings",
  description,
  extraContent,
}: {
  formData: QuestionFormData;
  onChange: <K extends keyof QuestionFormData>(field: K, value: QuestionFormData[K]) => void;
  title?: string;
  description?: string;
  extraContent?: ReactNode;
}) {
  const renderContent = () => {
    switch (formData.questionType) {
      case "Single Choice":
      case "Multiple Choices": {
        const isMultiple = formData.questionType === "Multiple Choices";
        const options = Array.isArray(formData.options) ? formData.options : [];
        const correctIds = isMultiple 
          ? (formData.correctAnswers?.optionIds || []) 
          : (formData.correctAnswers?.optionId ? [formData.correctAnswers.optionId] : []);

        const updateOption = (index: number, val: string) => {
          const newOpts = [...options];
          newOpts[index] = { ...newOpts[index], text: val };
          onChange("options", newOpts);
        };

        const toggleCorrect = (id: string) => {
          if (!isMultiple) {
            onChange("correctAnswers", { optionId: id });
          } else {
            const newIds = correctIds.includes(id) 
              ? correctIds.filter((cid: string) => cid !== id) 
              : [...correctIds, id];
            onChange("correctAnswers", { optionIds: newIds });
          }
        };

        const addOption = () => {
          const newId = `opt_${Date.now()}`;
          onChange("options", [...options, { id: newId, text: "" }]);
        };

        const removeOption = (index: number, id: string) => {
          const newOpts = options.filter((_: any, i: number) => i !== index);
          onChange("options", newOpts);
          if (!isMultiple && correctIds.includes(id)) {
            onChange("correctAnswers", { optionId: newOpts[0]?.id || "" });
          } else if (isMultiple && correctIds.includes(id)) {
            onChange("correctAnswers", { optionIds: correctIds.filter((cid: string) => cid !== id) });
          }
        };

        return (
          <div className="space-y-4 animate-in fade-in duration-500">
            <div className="flex items-center gap-2 mb-2">
              <div className="p-2 bg-yellow-100 rounded-lg text-yellow-600">
                <ListOrdered className="h-5 w-5" />
              </div>
              <div>
                <Label className="block text-sm font-bold text-slate-800">Answer Options</Label>
                <p className="text-xs text-slate-500">
                  {isMultiple ? "Check all correct answers" : "Select the single correct answer"}
                </p>
              </div>
            </div>

            <div className="space-y-3">
              {options.map((opt: any, index: number) => {
                const isCorrect = correctIds.includes(opt.id);
                return (
                  <div
                    key={opt.id}
                    className={`group flex items-center gap-3 rounded-xl border-2 px-4 py-3 transition-all duration-300 hover:shadow-md ${
                      isCorrect ? "border-yellow-500 bg-yellow-50/50" : "border-slate-200 bg-white hover:border-yellow-300"
                    }`}
                  >
                    <button
                      type="button"
                      onClick={() => toggleCorrect(opt.id)}
                      className={`flex h-6 w-6 shrink-0 items-center justify-center transition-all duration-200 ${
                        !isMultiple ? "rounded-full" : "rounded-md"
                      } ${
                        isCorrect
                          ? "bg-yellow-500 text-white border-transparent"
                          : "border-2 border-slate-300 bg-white hover:border-yellow-400"
                      }`}
                    >
                      {isCorrect && <Check className="h-4 w-4" />}
                    </button>
                    <span className="w-6 text-sm font-bold text-slate-400">
                      {getOptionLabel(index)}
                    </span>
                    <Input
                      type="text"
                      placeholder={`Option ${getOptionLabel(index)}`}
                      value={opt.text}
                      onChange={(e) => updateOption(index, e.target.value)}
                      className="flex-1 border-none bg-transparent shadow-none focus-visible:ring-0 px-0 text-sm font-medium text-slate-700 placeholder:text-slate-400"
                    />
                    {options.length > 2 && (
                      <button
                        type="button"
                        onClick={() => removeOption(index, opt.id)}
                        className="opacity-0 group-hover:opacity-100 p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-md transition-all"
                      >
                        <X className="h-4 w-4" />
                      </button>
                    )}
                  </div>
                );
              })}
              <Button
                type="button"
                onClick={addOption}
                variant="outline"
                className="w-full mt-2 border-dashed border-2 border-slate-300 text-slate-500 hover:text-yellow-600 hover:border-yellow-300 hover:bg-yellow-50 transition-all rounded-xl py-6"
              >
                <Plus className="h-4 w-4 mr-2" /> Add Option
              </Button>
            </div>
          </div>
        );
      }

      case "True/False": {
        const isTrue = formData.correctAnswers?.value === true;
        const setCorrect = (val: boolean) => onChange("correctAnswers", { value: val });
        const labels = formData.options || { trueLabel: "True", falseLabel: "False" };

        return (
          <div className="space-y-4 animate-in fade-in duration-500">
            <div className="flex items-center gap-2 mb-2">
              <div className="p-2 bg-emerald-100 rounded-lg text-emerald-600">
                <Check className="h-5 w-5" />
              </div>
              <div>
                <Label className="block text-sm font-bold text-slate-800">Correct Answer</Label>
                <p className="text-xs text-slate-500">Select whether the statement is true or false</p>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              {[
                { label: labels.trueLabel, value: true },
                { label: labels.falseLabel, value: false },
              ].map((opt) => {
                const isCorrect = isTrue === opt.value;
                return (
                  <button
                    key={opt.label}
                    type="button"
                    onClick={() => setCorrect(opt.value)}
                    className={`flex flex-col items-center justify-center p-6 rounded-2xl border-2 transition-all duration-300 hover:shadow-lg ${
                      isCorrect 
                        ? "border-emerald-500 bg-emerald-50 text-emerald-700" 
                        : "border-slate-200 bg-white text-slate-500 hover:border-emerald-300"
                    }`}
                  >
                    <div className={`flex h-8 w-8 items-center justify-center rounded-full mb-3 ${isCorrect ? 'bg-emerald-500 text-white' : 'bg-slate-100'}`}>
                      {isCorrect && <Check className="h-5 w-5" />}
                    </div>
                    <span className="font-bold">{opt.label}</span>
                  </button>
                );
              })}
            </div>
          </div>
        );
      }

      case "Short Answer":
      case "Essay": {
        const keywords = formData.correctAnswers?.keyPointsExpected || [];
        const updateKeyword = (index: number, val: string) => {
          const newKws = [...keywords];
          newKws[index] = val;
          onChange("correctAnswers", { ...formData.correctAnswers, keyPointsExpected: newKws });
        };
        const removeKeyword = (index: number) => {
          onChange("correctAnswers", { ...formData.correctAnswers, keyPointsExpected: keywords.filter((_: any, i: number) => i !== index) });
        };

        return (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="space-y-4">
              <div className="flex items-center gap-2">
                <div className="p-2 bg-blue-100 rounded-lg text-blue-600">
                  <MessageSquare className="h-5 w-5" />
                </div>
                <div>
                  <Label className="block text-sm font-bold text-slate-800">Word Count Limits</Label>
                  <p className="text-xs text-slate-500">Set boundaries for the response</p>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-xs font-semibold text-slate-600">Minimum Words</Label>
                  <Input 
                    type="number" 
                    value={formData.options?.minWords || 0} 
                    onChange={(e) => onChange("options", { ...formData.options, minWords: parseInt(e.target.value) || 0 })}
                    className="rounded-xl border-slate-200 focus:ring-blue-500/50"
                  />
                </div>
                <div className="space-y-2">
                  <Label className="text-xs font-semibold text-slate-600">Maximum Words</Label>
                  <Input 
                    type="number" 
                    value={formData.options?.maxWords || 0} 
                    onChange={(e) => onChange("options", { ...formData.options, maxWords: parseInt(e.target.value) || 0 })}
                    className="rounded-xl border-slate-200 focus:ring-blue-500/50"
                  />
                </div>
              </div>
            </div>

            <div className="space-y-4">
              <div>
                <Label className="block text-sm font-bold text-slate-800">Expected Key Points</Label>
                <p className="text-xs text-slate-500">Keywords the AI will look for when grading</p>
              </div>
              <div className="flex flex-wrap gap-2 p-4 bg-slate-50 rounded-xl border border-slate-200">
                {keywords.map((kw: string, index: number) => (
                  <div key={index} className="flex items-center gap-1 bg-white border border-slate-300 rounded-lg pl-3 pr-1 py-1 shadow-sm focus-within:ring-2 focus-within:ring-blue-500/50 focus-within:border-blue-500 transition-all">
                    <input
                      type="text"
                      value={kw}
                      onChange={(e) => updateKeyword(index, e.target.value)}
                      placeholder="Keyword"
                      className="border-none bg-transparent text-sm w-24 focus:outline-none font-medium text-slate-700"
                    />
                    <button type="button" onClick={() => removeKeyword(index)} className="p-1 text-slate-400 hover:text-red-500 rounded-md hover:bg-red-50 transition-colors">
                      <X className="h-3 w-3" />
                    </button>
                  </div>
                ))}
                <button
                  type="button"
                  onClick={() => onChange("correctAnswers", { ...formData.correctAnswers, keyPointsExpected: [...keywords, ""] })}
                  className="flex items-center justify-center h-8 w-8 bg-blue-100 text-blue-600 rounded-lg hover:bg-blue-200 transition-colors"
                >
                  <Plus className="h-4 w-4" />
                </button>
              </div>
            </div>

            <div className="space-y-3">
              <Label className="block text-sm font-bold text-slate-800">Model Answer Reference</Label>
              <Textarea
                placeholder="Provide a perfect example answer for AI grading reference..."
                value={formData.correctAnswers?.modelAnswerReference || ""}
                onChange={(e) => onChange("correctAnswers", { ...formData.correctAnswers, modelAnswerReference: e.target.value })}
                className="rounded-xl border-slate-200 min-h-[100px] focus:ring-blue-500/50"
              />
            </div>
          </div>
        );
      }

      case "Fill in the Blank": {
        const answers = formData.correctAnswers?.answers || [];

        return (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="space-y-3">
              <div className="flex items-center gap-2">
                <div className="p-2 bg-pink-100 rounded-lg text-pink-600">
                  <Edit3 className="h-5 w-5" />
                </div>
                <div>
                  <Label className="block text-sm font-bold text-slate-800">Template Text</Label>
                  <p className="text-xs text-slate-500">Use `[blank_1]`, `[blank_2]`, etc. to define blanks</p>
                </div>
              </div>
              <Textarea
                value={formData.options?.template || ""}
                onChange={(e) => onChange("options", { template: e.target.value })}
                placeholder="The [blank_1] is the powerhouse of the [blank_2]."
                className="rounded-xl border-slate-200 min-h-[100px] focus:ring-pink-500/50 text-base leading-relaxed"
              />
            </div>

            <div className="space-y-3">
              <Label className="block text-sm font-bold text-slate-800">Accepted Answers per Blank</Label>
              <div className="space-y-3">
                {answers.map((ansGroup: string[], index: number) => (
                  <div key={index} className="p-4 bg-slate-50 rounded-xl border border-slate-200 flex flex-col gap-2">
                    <span className="text-xs font-bold text-pink-600 uppercase tracking-wider">[blank_{index + 1}]</span>
                    <div className="flex flex-wrap gap-2">
                      {ansGroup.map((ans, i) => (
                        <div key={i} className="flex items-center gap-1 bg-white border border-slate-300 rounded-lg pl-3 pr-1 py-1 shadow-sm">
                          <input
                            value={ans}
                            onChange={(e) => {
                              const newGroups = [...answers];
                              newGroups[index][i] = e.target.value;
                              onChange("correctAnswers", { answers: newGroups });
                            }}
                            className="border-none bg-transparent text-sm w-24 focus:outline-none font-medium text-slate-700"
                          />
                          <button 
                            type="button"
                            onClick={() => {
                              const newGroups = [...answers];
                              newGroups[index] = newGroups[index].filter((_: any, idx: number) => idx !== i);
                              onChange("correctAnswers", { answers: newGroups });
                            }} 
                            className="p-1 text-slate-400 hover:text-red-500"
                          >
                            <X className="h-3 w-3" />
                          </button>
                        </div>
                      ))}
                      <button
                        type="button"
                        onClick={() => {
                          const newGroups = [...answers];
                          newGroups[index] = [...newGroups[index], ""];
                          onChange("correctAnswers", { answers: newGroups });
                        }}
                        className="flex items-center justify-center h-8 w-8 bg-pink-100 text-pink-600 rounded-lg hover:bg-pink-200"
                      >
                        <Plus className="h-4 w-4" />
                      </button>
                    </div>
                  </div>
                ))}
                <div className="flex gap-2">
                  <Button
                    type="button"
                    variant="outline"
                    onClick={() => onChange("correctAnswers", { answers: [...answers, [""]] })}
                    className="text-pink-600 border-pink-200 hover:bg-pink-50"
                  >
                    <Plus className="h-4 w-4 mr-2" /> Add Blank Definition
                  </Button>
                </div>
              </div>
            </div>
          </div>
        );
      }

      case "Matching": {
        const leftSide = formData.options?.leftSide || [];
        const rightSide = formData.options?.rightSide || [];
        const pairs = formData.correctAnswers?.pairs || [];

        return (
          <div className="space-y-4 animate-in fade-in duration-500">
             <div className="flex items-center gap-2 mb-4">
              <div className="p-2 bg-orange-100 rounded-lg text-orange-600">
                <LinkIcon className="h-5 w-5" />
              </div>
              <div>
                <Label className="block text-sm font-bold text-slate-800">Matching Pairs</Label>
                <p className="text-xs text-slate-500">Define the pairs; they will be shuffled for participants.</p>
              </div>
            </div>

            <div className="space-y-3">
              {pairs.map((pair: any, index: number) => {
                const lText = leftSide.find((l:any) => l.id === pair.leftId)?.text || "";
                const rText = rightSide.find((r:any) => r.id === pair.rightId)?.text || "";

                return (
                  <div key={index} className="flex items-center gap-3 p-2 bg-slate-50 rounded-xl border border-slate-200">
                    <Input
                      placeholder="Left item"
                      value={lText}
                      onChange={(e) => {
                        const newL = [...leftSide];
                        newL[index] = { id: pair.leftId, text: e.target.value };
                        onChange("options", { ...formData.options, leftSide: newL });
                      }}
                      className="bg-white rounded-lg border-slate-300"
                    />
                    <div className="text-orange-400">
                      <LinkIcon className="h-4 w-4" />
                    </div>
                    <Input
                      placeholder="Right item"
                      value={rText}
                      onChange={(e) => {
                        const newR = [...rightSide];
                        newR[index] = { id: pair.rightId, text: e.target.value };
                        onChange("options", { ...formData.options, rightSide: newR });
                      }}
                      className="bg-white rounded-lg border-slate-300"
                    />
                    {pairs.length > 2 && (
                      <button
                        type="button"
                        onClick={() => {
                          onChange("options", {
                            leftSide: leftSide.filter((_:any, i:number) => i !== index),
                            rightSide: rightSide.filter((_:any, i:number) => i !== index),
                          });
                          onChange("correctAnswers", {
                            pairs: pairs.filter((_:any, i:number) => i !== index)
                          });
                        }}
                        className="p-2 text-slate-400 hover:text-red-500 bg-white rounded-lg border border-slate-200"
                      >
                        <X className="h-4 w-4" />
                      </button>
                    )}
                  </div>
                );
              })}
              <Button
                type="button"
                variant="outline"
                onClick={() => {
                  const newIdx = Date.now();
                  const lId = `l_${newIdx}`;
                  const rId = `r_${newIdx}`;
                  onChange("options", {
                    leftSide: [...leftSide, { id: lId, text: "" }],
                    rightSide: [...rightSide, { id: rId, text: "" }]
                  });
                  onChange("correctAnswers", {
                    pairs: [...pairs, { leftId: lId, rightId: rId }]
                  });
                }}
                className="w-full border-dashed border-2 border-slate-300 text-slate-500 hover:text-orange-600 hover:border-orange-300 hover:bg-orange-50"
              >
                <Plus className="h-4 w-4 mr-2" /> Add Pair
              </Button>
            </div>
          </div>
        );
      }

      case "Ordering": {
        const options = formData.options || [];

        const moveOpt = (index: number, dir: 'up'|'down') => {
          const target = dir === 'up' ? index - 1 : index + 1;
          if (target < 0 || target >= options.length) return;
          const newOpts = [...options];
          [newOpts[index], newOpts[target]] = [newOpts[target], newOpts[index]];
          onChange("options", newOpts);
          onChange("correctAnswers", { sequence: newOpts.map((o:any) => o.id) });
        };

        return (
          <div className="space-y-4 animate-in fade-in duration-500">
            <div className="flex items-center gap-2 mb-4">
              <div className="p-2 bg-purple-100 rounded-lg text-purple-600">
                <ListOrdered className="h-5 w-5" />
              </div>
              <div>
                <Label className="block text-sm font-bold text-slate-800">Correct Sequence</Label>
                <p className="text-xs text-slate-500">Add items in the exact order they should be arranged.</p>
              </div>
            </div>

            <div className="space-y-3">
              {options.map((opt: any, index: number) => (
                <div key={opt.id} className="flex items-center gap-3 p-3 bg-white rounded-xl border border-slate-200 shadow-sm transition hover:shadow-md hover:border-purple-300">
                  <div className="flex flex-col gap-1">
                    <button type="button" onClick={() => moveOpt(index, 'up')} disabled={index === 0} className="text-slate-400 hover:text-purple-600 disabled:opacity-30 p-1.5 sm:p-2 transition-colors rounded-md hover:bg-purple-50">
                      <ChevronUp className="h-5 w-5 sm:h-6 sm:w-6" />
                    </button>
                    <button type="button" onClick={() => moveOpt(index, 'down')} disabled={index === options.length - 1} className="text-slate-400 hover:text-purple-600 disabled:opacity-30 p-1.5 sm:p-2 transition-colors rounded-md hover:bg-purple-50">
                      <ChevronDown className="h-5 w-5 sm:h-6 sm:w-6" />
                    </button>
                  </div>
                  <div className="flex h-8 w-8 items-center justify-center bg-purple-100 text-purple-700 font-bold rounded-md text-sm shrink-0">
                    {index + 1}
                  </div>
                  <Input
                    value={opt.text}
                    onChange={(e) => {
                      const newOpts = [...options];
                      newOpts[index] = { ...opt, text: e.target.value };
                      onChange("options", newOpts);
                    }}
                    placeholder={`Item ${index + 1}`}
                    className="flex-1 border-none bg-transparent shadow-none focus-visible:ring-0 px-0 font-medium"
                  />
                  {options.length > 2 && (
                    <button
                      type="button"
                      onClick={() => {
                        const newOpts = options.filter((_:any, i:number) => i !== index);
                        onChange("options", newOpts);
                        onChange("correctAnswers", { sequence: newOpts.map((o:any) => o.id) });
                      }}
                      className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-md"
                    >
                      <X className="h-4 w-4" />
                    </button>
                  )}
                </div>
              ))}
              <Button
                type="button"
                variant="outline"
                onClick={() => {
                  const id = `opt_${Date.now()}`;
                  const newOpts = [...options, { id, text: "" }];
                  onChange("options", newOpts);
                  onChange("correctAnswers", { sequence: newOpts.map((o:any) => o.id) });
                }}
                className="w-full border-dashed border-2 border-slate-300 text-slate-500 hover:text-purple-600 hover:border-purple-300 hover:bg-purple-50"
              >
                <Plus className="h-4 w-4 mr-2" /> Add Step
              </Button>
            </div>
          </div>
        );
      }

      case "Rating Scale": {
        const min = formData.options?.min || 1;
        const max = formData.options?.max || 5;
        const lowLabel = formData.options?.lowLabel || "";
        const highLabel = formData.options?.highLabel || "";

        return (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="flex items-center gap-2">
              <div className="p-2 bg-yellow-100 rounded-lg text-yellow-600">
                <Star className="h-5 w-5" />
              </div>
              <div>
                <Label className="block text-sm font-bold text-slate-800">Rating Scale Configuration</Label>
                <p className="text-xs text-slate-500">Configure the range and labels for the rating.</p>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-6 p-5 bg-slate-50 rounded-2xl border border-slate-200">
              <div className="space-y-4">
                <div className="space-y-2">
                  <Label className="text-xs font-bold text-slate-600 uppercase">Min Value</Label>
                  <Select
                    value={String(min)}
                    onChange={(e) => onChange("options", { ...formData.options, min: parseInt(e.target.value) })}
                    className="bg-white"
                  >
                    <option value="0">0</option>
                    <option value="1">1</option>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label className="text-xs font-bold text-slate-600 uppercase">Min Label</Label>
                  <Input 
                    value={lowLabel}
                    onChange={(e) => onChange("options", { ...formData.options, lowLabel: e.target.value })}
                    placeholder="e.g. Strongly Disagree"
                    className="bg-white"
                  />
                </div>
              </div>
              <div className="space-y-4">
                <div className="space-y-2">
                  <Label className="text-xs font-bold text-slate-600 uppercase">Max Value</Label>
                  <Select
                    value="5"
                    disabled
                    className="bg-slate-100 text-slate-500 cursor-not-allowed opacity-70"
                  >
                    <option value="5">5</option>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label className="text-xs font-bold text-slate-600 uppercase">Max Label</Label>
                  <Input 
                    value={highLabel}
                    onChange={(e) => onChange("options", { ...formData.options, highLabel: e.target.value })}
                    placeholder="e.g. Strongly Agree"
                    className="bg-white"
                  />
                </div>
              </div>
            </div>
          </div>
        );
      }

      default:
        return (
          <div className="flex flex-col items-center justify-center p-8 text-slate-400 border-2 border-dashed border-slate-200 rounded-2xl">
            <FileQuestion className="h-12 w-12 mb-3 text-slate-300" />
            <p className="text-sm font-medium">Select a question type to configure its settings</p>
          </div>
        );
    }
  };

  return (
    <Card className="border-slate-200/60 shadow-sm bg-white/50 backdrop-blur-sm">
      <CardHeader className="bg-slate-50/50 border-b border-slate-100 rounded-t-2xl">
        <CardTitle className="text-lg text-slate-800">{title}</CardTitle>
        {description ? <CardDescription>{description}</CardDescription> : null}
      </CardHeader>
      <CardContent className="pt-6">
        {renderContent()}
        {extraContent}
      </CardContent>
    </Card>
  );
}

"use client";

import Link from "next/link";
import { useMemo, useState, useEffect } from "react";
import QuestionsTableInteractive from "./QuestionsTableInteractive";
import DeleteQuestionModal from "@/src/components/content/question/detail/DeleteQuestionModal";
