"use client";

import { useState, useRef, useEffect, useMemo } from "react";
import { createPortal } from "react-dom";
import { ChevronDown, Search } from "lucide-react";
import { cn } from "@/src/lib/utils";

export type DropdownOption = {
  value: string;
  label: string;
};

export function DropdownSelect({
  value,
  options,
  onChange,
  className,
  searchable = false,
  searchPlaceholder = "Search...",
}: {
  value: string;
  options: DropdownOption[];
  onChange: (val: string) => void;
  className?: string;
  searchable?: boolean;
  searchPlaceholder?: string;
}) {
  const [isOpen, setIsOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const selectRef = useRef<HTMLDivElement>(null);
  const buttonRef = useRef<HTMLButtonElement>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const searchInputRef = useRef<HTMLInputElement>(null);
  const [position, setPosition] = useState({ top: 0, left: 0, width: 0 });
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  const updatePosition = () => {
    if (buttonRef.current) {
      const rect = buttonRef.current.getBoundingClientRect();
      setPosition({
        top: rect.bottom + window.scrollY + 4,
        left: rect.left + window.scrollX,
        width: rect.width,
      });
    }
  };

  useEffect(() => {
    if (isOpen) {
      updatePosition();
      window.addEventListener("resize", updatePosition);
      window.addEventListener("scroll", updatePosition, true);
      return () => {
        window.removeEventListener("resize", updatePosition);
        window.removeEventListener("scroll", updatePosition, true);
      };
    }
  }, [isOpen]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (
        selectRef.current && 
        !selectRef.current.contains(event.target as Node) &&
        dropdownRef.current &&
        !dropdownRef.current.contains(event.target as Node)
      ) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => {
    if (!isOpen) {
      setSearchQuery("");
    } else if (searchable && searchInputRef.current) {
      setTimeout(() => {
        searchInputRef.current?.focus();
      }, 0);
    }
  }, [isOpen, searchable]);

  const selectedOption = options.find((opt) => opt.value === value) || options[0];

  const filteredOptions = useMemo(() => {
    if (!searchable || !searchQuery.trim()) return options;
    const query = searchQuery.toLowerCase();
    return options.filter((opt) => opt.label.toLowerCase().includes(query));
  }, [options, searchable, searchQuery]);

  const toggleDropdown = () => {
    if (!isOpen) {
      updatePosition();
    }
    setIsOpen(!isOpen);
  };

  return (
    <div className={cn("relative w-full", className)} ref={selectRef}>
      <button
        ref={buttonRef}
        type="button"
        onClick={toggleDropdown}
        className="flex w-full items-center justify-between gap-2 rounded-xl border border-slate-200 bg-white px-4 py-2.5 text-sm font-medium text-slate-700 shadow-sm transition-all focus:border-indigo-500 focus:outline-none focus:ring-2 focus:ring-indigo-500/50"
      >
        <span className="truncate">{selectedOption?.label}</span>
        <ChevronDown
          className={`h-4 w-4 shrink-0 text-slate-400 transition-transform duration-200 ${
            isOpen ? "rotate-180" : ""
          }`}
        />
      </button>

      {mounted && isOpen && createPortal(
        <div 
          ref={dropdownRef}
          style={{ 
            top: position.top, 
            left: position.left, 
            width: position.width 
          }}
          className="absolute z-[9999] flex flex-col overflow-hidden rounded-xl border border-slate-200 bg-white shadow-xl ring-1 ring-black/5 animate-in fade-in-0 zoom-in-95 duration-150"
        >
          {searchable && (
            <div className="border-b border-slate-100 p-2">
              <div className="relative">
                <Search className="absolute left-2.5 top-1/2 h-3.5 w-3.5 -translate-y-1/2 text-slate-400" />
                <input
                  ref={searchInputRef}
                  type="text"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  placeholder={searchPlaceholder}
                  className="w-full rounded-lg border-none bg-slate-50 py-2 pl-8 pr-3 text-sm text-slate-700 focus:bg-slate-100 focus:outline-none focus:ring-0"
                />
              </div>
            </div>
          )}

          <div className="max-h-75 overflow-y-auto py-1">
            {filteredOptions.length === 0 ? (
              <div className="px-4 py-3 text-center text-sm text-slate-500">
                No results found
              </div>
            ) : (
              filteredOptions.map((opt) => (
                <button
                  key={opt.value}
                  type="button"
                  onClick={() => {
                    onChange(opt.value);
                    setIsOpen(false);
                  }}
                  className={`flex w-full items-center px-4 py-2.5 text-sm transition-colors hover:bg-slate-50 hover:text-indigo-600 ${
                    value === opt.value ? "bg-slate-50 font-bold text-indigo-600" : "text-slate-600 font-medium"
                  }`}
                >
                  {opt.label}
                </button>
              ))
            )}
          </div>
        </div>,
        document.body
      )}
    </div>
  );
}

import { useState, useTransition, useEffect } from "react";
import { useRouter, usePathname } from "next/navigation";
import { assessmentFormSchema } from "@/src/schemas/assessment-form.schema";
import type {
  AssessmentGradeLabel,
  NewAssessmentFormData,
} from "@/src/types/assessment-form.types";
import { createAssessmentAction, updateAssessmentAction, publishAssessmentAction } from "@/src/lib/actions/assessment.actions";
import { toast } from "sonner";
import { useTopicStore } from "@/src/stores/topic-store";

const defaultFormData: NewAssessmentFormData = {
  name: "",
  type: "QUIZ",
  description: "",
  ownerTopicId: "",
  status: "DRAFT",
  participantIdentity: "EXTERNAL",
  sessionMode: "SELF_PACED",
  questionSelection: "MANUAL",
  selectedBankId: "",
  selectedQuestionIds: [],
  totalQuestions: 10,
  selectionRules: [
    { difficulty: "Easy", count: 3 },
    { difficulty: "Medium", count: 5 },
    { difficulty: "Hard", count: 2 },
  ],
  enableTimeLimit: false,
  timeLimitMinutes: 0,
  startsAt: "",
  endsAt: "",
  passMark: 50,
  shuffleQuestions: true,
  gradeLabels: [
    { grade: "A", minPercent: 90 },
    { grade: "B", minPercent: 80 },
    { grade: "C", minPercent: 70 },
    { grade: "D", minPercent: 60 },
    { grade: "F", minPercent: 0 },
  ],
  showResults: "IMMEDIATELY",
};

const stepValidationFields: Record<1 | 2 | 3, string[]> = {
  1: ["name"],
  2: [
    "sessionMode",
    "questionSelection",
    "participantIdentity",
    "timeLimitMinutes",
    "startsAt",
    "endsAt",
    "passMark",
    "gradeLabels",
    "showResults",
  ],
  3: [
    "selectedBankId",
    "selectedQuestionIds",
    "totalQuestions",
    "selectionRules",
  ],
};

export function useAssessmentForm({
  mode = "create",
  assessmentId,
  initialFormData,
}: {
  mode?: "create" | "edit" | "duplicate";
  assessmentId?: string;
  initialFormData?: NewAssessmentFormData;
}) {
  const router = useRouter();
  const pathname = usePathname();
  const activeTopic = useTopicStore((s) => s.activeTopic);

  const [currentStep, setCurrentStep] = useState<1 | 2 | 3>(1);
  const [questionSearch, setQuestionSearch] = useState("");
  const [formData, setFormData] = useState<NewAssessmentFormData>(
    initialFormData ?? { ...defaultFormData, ownerTopicId: activeTopic?.id || "" },
  );
  const [isPending, startTransition] = useTransition();

  useEffect(() => {
    setCurrentStep(1);
    if (mode === "create" && pathname === "/assessments/new") {
      setFormData({ ...defaultFormData, ownerTopicId: activeTopic?.id || "" });
      setQuestionSearch("");
    } else if (initialFormData) {
      setFormData(initialFormData);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [pathname, mode, assessmentId]);

  // Keep ownerTopicId in sync with activeTopic if it hydrates after mount or changes
  useEffect(() => {
    if (mode === "create" && activeTopic?.id) {
      setFormData((prev) => {
        if (prev.ownerTopicId !== activeTopic.id) {
          return { ...prev, ownerTopicId: activeTopic.id };
        }
        return prev;
      });
    }
  }, [mode, activeTopic?.id]);

  const getStepValidationMessages = (step: 1 | 2 | 3) => {
    const dataToValidate = {
      ...formData,
      ownerTopicId: activeTopic?.id || formData.ownerTopicId || "TEMP_TOPIC" // satisfy schema for missing topic since we handle it externally
    };
    const validationResult = assessmentFormSchema.safeParse(dataToValidate);

    if (validationResult.success) {
      return [];
    }

    const allowedFields = stepValidationFields[step];

    return Array.from(
      new Set(
        validationResult.error.issues
          .filter((issue) =>
            allowedFields.includes(String(issue.path[0] ?? "")),
          )
          .map((issue) => issue.message),
      ),
    );
  };

  const isStepComplete = (step: number) => {
    if (![1, 2, 3].includes(step)) {
      return false;
    }

    return getStepValidationMessages(step as 1 | 2 | 3).length === 0;
  };

  const canContinue = isStepComplete(currentStep);

  const handleChange = <K extends keyof NewAssessmentFormData>(
    field: K,
    value: NewAssessmentFormData[K],
  ) => {
    setFormData((current) => {
      let nextQuestionSelection = current.questionSelection;

      // If switching to REAL_TIME, force MANUAL selection
      if (field === "sessionMode" && value === "REAL_TIME") {
        nextQuestionSelection = "MANUAL";
      }

      return {
        ...current,
        [field]: value,
        questionSelection: field === "questionSelection" ? (value as any) : nextQuestionSelection,
      };
    });
  };

  const handleNext = () => {
    if (currentStep >= 4) {
      return;
    }

    if (!canContinue) {
      const messages = getStepValidationMessages(currentStep);
      messages.forEach((msg) => toast.error(msg));
      return;
    }

    setCurrentStep((currentStep + 1) as 1 | 2 | 3);
  };

  const handlePrevious = () => {
    if (currentStep <= 1) {
      return;
    }

    setCurrentStep((currentStep - 1) as 1 | 2 | 3);
  };

  const handleQuestionToggle = (questionId: string) => {
    setFormData((current) => {
      const alreadySelected = current.selectedQuestionIds.includes(questionId);

      return {
        ...current,
        selectedQuestionIds: alreadySelected
          ? current.selectedQuestionIds.filter((id) => id !== questionId)
          : [...current.selectedQuestionIds, questionId],
      };
    });
  };

  const handleSelectionRuleChange = (
    difficulty: "Easy" | "Medium" | "Hard",
    count: number,
  ) => {
    setFormData((current) => ({
      ...current,
      selectionRules: current.selectionRules.map((rule) =>
        rule.difficulty === difficulty ? { ...rule, count } : rule,
      ),
    }));
  };

  const handleGradeLabelChange = (
    index: number,
    field: keyof AssessmentGradeLabel,
    value: string | number,
  ) => {
    setFormData((current) => ({
      ...current,
      gradeLabels: current.gradeLabels.map((label, currentIndex) =>
        currentIndex === index ? { ...label, [field]: value } : label,
      ),
    }));
  };

  const handleAddGradeLabel = () => {
    setFormData((current) => ({
      ...current,
      gradeLabels: [...current.gradeLabels, { grade: "", minPercent: 0 }],
    }));
  };

  const handleRemoveGradeLabel = (index: number) => {
    setFormData((current) => ({
      ...current,
      gradeLabels: current.gradeLabels.filter(
        (_, currentIndex) => currentIndex !== index,
      ),
    }));
  };

  const destination = mode === "edit" && assessmentId ? `/assessments/${assessmentId}` : "/assessments";

  const handleSubmit = (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();

    // Prevent accidental auto-saving when pressing Enter on steps 1 and 2
    if (currentStep < 3) {
      return;
    }

    if (!activeTopic && !formData.ownerTopicId) {
      toast.error("Owner topic is required.");
      return;
    }

    const submitData = {
      ...formData,
      ownerTopicId: mode === "create" ? (activeTopic?.id || formData.ownerTopicId) : (formData.ownerTopicId || activeTopic?.id)
    };

    if (submitData.questionSelection === "MANUAL" && submitData.selectedQuestionIds.length === 0) {
      toast.error("Select at least one question for manual question selection.");
      return;
    }

    const validationResult = assessmentFormSchema.safeParse(submitData);

    if (!validationResult.success) {
      const errorMessages = Array.from(
        new Set(validationResult.error.issues.map((issue) => issue.message)),
      );
      errorMessages.forEach((msg) => toast.error(msg));
      return;
    }


    startTransition(async () => {
      let res;
      if (mode === "edit" && assessmentId) {
        res = await updateAssessmentAction(assessmentId, submitData);
      } else {
        res = await createAssessmentAction(submitData.ownerTopicId || "", submitData);
      }

      if (!res.success) {
        toast.error(res.error || "Failed to save assessment");
      } else {
        toast.success(mode === "edit" ? "Assessment updated successfully!" : "Assessment created successfully!");
        router.refresh();
        router.push(destination);
      }
    });
  };

  const handlePublish = () => {
    if (!activeTopic && !formData.ownerTopicId) {
      toast.error("Owner topic is required.");
      return;
    }

    const submitData = {
      ...formData,
      ownerTopicId: mode === "create" ? (activeTopic?.id || formData.ownerTopicId) : (formData.ownerTopicId || activeTopic?.id)
    };

    if (submitData.questionSelection === "MANUAL" && submitData.selectedQuestionIds.length === 0) {
      toast.error("Select at least one question for manual question selection.");
      return;
    }

    const validationResult = assessmentFormSchema.safeParse(submitData);

    if (!validationResult.success) {
      const errorMessages = Array.from(
        new Set(validationResult.error.issues.map((issue) => issue.message)),
      );
      errorMessages.forEach((msg) => toast.error(msg));
      return;
    }


    startTransition(async () => {
      let currentAssessmentId = assessmentId;

      // If creating new or duplicating and publishing immediately
      if (mode !== "edit" || !currentAssessmentId) {
        const createRes = await createAssessmentAction(submitData.ownerTopicId || "", submitData);
        if (!createRes.success || !createRes.assessment) {
          toast.error(createRes.error || "Failed to create assessment for publishing");
          return;
        }
        currentAssessmentId = (createRes.assessment as any).id;
      } else {
        // If editing existing, save draft first
        const updateRes = await updateAssessmentAction(currentAssessmentId, submitData);
        if (!updateRes.success) {
          toast.error(updateRes.error || "Failed to save assessment before publishing");
          return;
        }
      }

      // Now publish
      if (!currentAssessmentId) return;
      const publishRes = await publishAssessmentAction(currentAssessmentId);
      if (!publishRes.success) {
        toast.error(publishRes.error || "Failed to publish assessment");
      } else {
        toast.success("Assessment published successfully!");
        router.refresh();
        router.push(destination);
      }
    });
  };

  return {
    currentStep,
    questionSearch,
    setQuestionSearch,
    formData,
    isPending,
    canContinue,
    handleChange,
    handleNext,
    handlePrevious,
    handleQuestionToggle,
    handleSelectionRuleChange,
    handleGradeLabelChange,
    handleAddGradeLabel,
    handleRemoveGradeLabel,
    handleSubmit,
    handlePublish,
    destination,
    activeTopic
  };
}

"use client";

import { useEffect, useState, useCallback, useRef } from "react";
import { io, Socket } from "socket.io-client";
import { RealtimeEvents, RoomRole } from "@/src/types/runtime.types";
import { getRealtimeUrl } from "@/src/lib/actions/runtime.actions";
import { toast } from "sonner";

export interface RoomState {
  roomId: string | null;
  phase: "lobby" | "waiting" | "active" | "correct" | "leaderboard" | "results";
  participants: any[];
  currentQuestion: any | null;
  endTime: string | null;
  questionNumber: number;
  totalQuestions: number;
  questionResults: any | null;
  leaderboard: any | null;
  myRank: any | null;
}

const initialRoomState: RoomState = {
  roomId: null,
  phase: "lobby",
  participants: [],
  currentQuestion: null,
  endTime: null,
  questionNumber: 0,
  totalQuestions: 0,
  questionResults: null,
  leaderboard: null,
  myRank: null,
};

export function useRealtimeSession(options?: { enabled?: boolean }) {
  const enabled = options?.enabled ?? true;
  const [socket, setSocket] = useState<Socket | null>(null);
  const [isConnected, setIsConnected] = useState(false);
  const [roomState, setRoomState] = useState<RoomState>(initialRoomState);

  const socketRef = useRef<Socket | null>(null);
  const joinParamsRef = useRef<{ roomId: string, role: RoomRole, participantId?: string, name?: string } | null>(null);

  useEffect(() => {
    if (!enabled) return;

    let activeSocket: Socket;

    async function initSocket() {
      const baseUrl = await getRealtimeUrl();
      const url = baseUrl || "http://localhost:3001";

      activeSocket = io(`${url}/realtime`, {
        transports: ["websocket"],
      });

      activeSocket.on("connect", () => {
        setIsConnected(true);
        if (joinParamsRef.current) {
          activeSocket.emit(RealtimeEvents.JOIN_ROOM, joinParamsRef.current);
        }
      });
      activeSocket.on("disconnect", () => setIsConnected(false));

      activeSocket.on(RealtimeEvents.ROOM_UPDATE, (data) => {
        setRoomState((prev) => ({
          ...prev,
          participants: data.participants || prev.participants,
          questionResults:
            typeof data.totalAnswered === "number"
              ? {
                  ...(prev.questionResults || {}),
                  totalAnswered: data.totalAnswered,
                  totalParticipants: data.totalParticipants,
                }
              : prev.questionResults,
        }));
      });

      activeSocket.on(RealtimeEvents.NEW_QUESTION, (data) => {
        // Backend returns: { questionNumber, totalQuestions, q, options, endTime }
        const parsedOptions = Array.isArray(data.options)
          ? data.options.map((option: any, index: number) => ({
              ...option,
              label: option.label || String.fromCharCode(65 + index),
            }))
          : [];
        const parsedQuestion = data.q
          ? {
              ...data.q,
              id: data.q.assessmentQuestionId || data.q.id,
              question: data.q.question || data.q.questionText || "",
              questionText: data.q.questionText || data.q.question || "",
              points: Number(data.q.points ?? 0),
              options: parsedOptions,
              correctOptionId: "",
            }
          : data;
        setRoomState((prev) => ({ 
          ...prev, 
          phase: "active", 
          currentQuestion: parsedQuestion,
          endTime: data.endTime || null,
          questionNumber: data.questionNumber || 0,
          totalQuestions: data.totalQuestions || 0,
          questionResults: null 
        }));
      });

      activeSocket.on(RealtimeEvents.Q_RESULTS, (data) => {
        setRoomState((prev) => ({ ...prev, phase: "correct", questionResults: data }));
      });

      activeSocket.on(RealtimeEvents.SHOW_RANK, (data) => {
        setRoomState((prev) => ({
          ...prev,
          phase: "leaderboard",
          leaderboard: data.top5,
          myRank: data.myRank ?? prev.myRank,
        }));
      });

      activeSocket.on(RealtimeEvents.SHOW_FINAL_RANK, (data) => {
        setRoomState((prev) => ({
          ...prev,
          phase: "results",
          leaderboard: Array.isArray(data) ? data : data.leaderboard,
        }));
      });

      activeSocket.on(RealtimeEvents.SESSION_ENDED, () => {
        setRoomState((prev) => ({ ...prev, phase: "results" }));
      });

      activeSocket.on(RealtimeEvents.ERROR, (error) => {
        toast.error(error.message || "Realtime error occurred");
      });

      setSocket(activeSocket);
      socketRef.current = activeSocket;
    }

    initSocket();

    return () => {
      if (socketRef.current) {
        socketRef.current.disconnect();
        socketRef.current = null;
      }
    };
  }, [enabled]);

  const joinRoom = useCallback((roomId: string, role: RoomRole, participantId?: string, name?: string) => {
    if (!socketRef.current) return;

    joinParamsRef.current = { roomId, role, participantId, name };

    setRoomState({
      ...initialRoomState,
      roomId,
      phase: role === RoomRole.HOST ? "lobby" : "waiting",
    });
    socketRef.current.emit(RealtimeEvents.JOIN_ROOM, { roomId, role, participantId, name });
  }, []);

  const resetRoomState = useCallback(() => {
    setRoomState(initialRoomState);
  }, []);

  const emitStartQuestion = useCallback((questionId?: string) => {
    if (!socketRef.current) return;
    socketRef.current.emit(RealtimeEvents.START_Q, { questionId });
  }, []);

  const emitRevealAnswers = useCallback((roomId?: string) => {
    if (!socketRef.current) return;
    socketRef.current.emit(RealtimeEvents.REVEAL_ANSWERS, { roomId });
  }, []);

  const emitSubmitAnswer = useCallback((response: any, timeTaken: number) => {
    if (!socketRef.current) return;
    const payload = Array.isArray(response)
      ? { response: { optionIds: response } }
      : typeof response === "boolean"
        ? { choice: String(response) }
        : typeof response === "string"
          ? { choice: response }
          : { response };
    socketRef.current.emit(RealtimeEvents.SUBMIT_ANS, { ...payload, timeTaken });
  }, []);

  return {
    socket,
    isConnected,
    roomState,
    resetRoomState,
    joinRoom,
    emitStartQuestion,
    emitRevealAnswers,
    emitSubmitAnswer,
  };
}

export type RealtimeSessionReturn = ReturnType<typeof useRealtimeSession>;

"use client";

import { useEffect, useState } from "react";
import { io } from "socket.io-client";
import { getRealtimeUrl } from "@/src/lib/actions/runtime.actions";
import { getAdminClientId } from "@/src/lib/actions/assessment.actions";
import { toast } from "sonner";

export function useAdminSockets() {
  const [updateTick, setUpdateTick] = useState(0);

  useEffect(() => {
    let activeSocket: any;

    async function initSocket() {
      try {
        const clientId = await getAdminClientId();
        if (!clientId) return;

        const baseUrl = await getRealtimeUrl();
        const url = baseUrl || "http://localhost:3001";

        activeSocket = io(`${url}/realtime`, {
          transports: ["websocket"],
        });

        activeSocket.on("connect", () => {
          activeSocket.emit("JOIN_ADMIN_ROOM", { clientId });
        });

        activeSocket.on("ASSESSMENT_UPDATED", (payload: { assessmentId: string; status: string }) => {
          // Trigger a re-fetch tick to silently update the UI
          setUpdateTick((t) => t + 1);
        });
      } catch (err) {
        console.error("Failed to init admin sockets", err);
      }
    }

    initSocket();

    return () => {
      if (activeSocket) {
        activeSocket.disconnect();
      }
    };
  }, []);

  return updateTick;
}

"use server";

import { revalidatePath } from "next/cache";
import { apiClient } from "@/src/lib/api-client";
import type { AssessmentCatalogItem, AssessmentDetailPageData } from "@/src/types";

export async function createAssessmentAction(topicId: string, data: any) {
  try {
    // 1. Create base assessment
    const basePayload = {
      name: data.name,
      type: data.type || "QUIZ",
      description: data.description,
    };
    const newAssessmentRaw = await apiClient.post<AssessmentCatalogItem | { data: AssessmentCatalogItem }>(`/topics/${topicId}/assessments`, basePayload);
    const newAssessment = (newAssessmentRaw as any).data || newAssessmentRaw;
    const assessmentId = newAssessment?.id;

    if (!assessmentId) {
      throw new Error("Failed to extract Assessment ID from the creation response.");
    }

    // 2. Update settings
    const settingsPayload = {
      mode: data.sessionMode,
      questionSelection: data.questionSelection,
      participantIdentity: data.participantIdentity,
      numQuestions: data.questionSelection === "MANUAL" 
        ? Math.max(1, data.selectedQuestionIds?.length || 1) 
        : Math.max(1, data.totalQuestions || 1),
      timeLimit: data.enableTimeLimit ? data.timeLimitMinutes : null,
      startsAt: data.startsAt || null,
      endsAt: data.endsAt || null,
      passMark: data.passMark,
      isShuffle: data.shuffleQuestions,
      showResults: data.showResults,
      gradeLabels: data.gradeLabels.map((l: any) => ({ name: l.grade, min: l.minPercent })),
      selectionRules: data.questionSelection === "DYNAMIC" ? {
        source: data.selectedBankId ? "bank" : "topic",
        bankId: data.selectedBankId || undefined,
        total: data.totalQuestions,
        distribution: {
          easy: data.selectionRules.find((r: any) => r.difficulty === "Easy")?.count || 0,
          medium: data.selectionRules.find((r: any) => r.difficulty === "Medium")?.count || 0,
          hard: data.selectionRules.find((r: any) => r.difficulty === "Hard")?.count || 0,
        }
      } : undefined,
    };
    await apiClient.patch(`/assessments/${assessmentId}/settings`, settingsPayload);

    // 3. Update questions (if manual and has questions)
    if (data.questionSelection === "MANUAL" && data.selectedQuestionIds && data.selectedQuestionIds.length > 0) {
      const payload = data.selectedQuestionIds.map((id: string) => ({ questionId: id }));
      await apiClient.post(`/assessments/${assessmentId}/questions`, payload);
    }

    revalidatePath("/assessments");
    revalidatePath("/search");
    revalidatePath("/");
    return { success: true, assessment: newAssessment };
  } catch (error: any) {
    console.error("Failed to create assessment:", error);
    return { success: false, error: error.message || "Failed to create assessment" };
  }
}

export async function updateAssessmentAction(id: string, data: any) {
  try {
    // 0. Check current status
    const currentAssessmentRaw = await apiClient.get<AssessmentDetailPageData>(`/assessments/${id}`);
    const currentAssessment = (currentAssessmentRaw as any).data || currentAssessmentRaw;
    const originalStatus = currentAssessment.status;
    const isPublishedOrArchived = originalStatus === "PUBLISHED" || originalStatus === "ARCHIVED";

    let updatedAssessment = currentAssessment;

    // 1. Update base assessment (skip if published/archived as backend blocks it)
    if (!isPublishedOrArchived) {
      const basePayload = {
        name: data.name,
        type: data.type || "QUIZ",
        description: data.description,
      };
      updatedAssessment = await apiClient.patch<AssessmentDetailPageData>(`/assessments/${id}`, basePayload);
    }

    // 2. Update settings
    const settingsPayload = {
      mode: data.sessionMode,
      questionSelection: data.questionSelection,
      participantIdentity: data.participantIdentity,
      numQuestions: data.questionSelection === "MANUAL" 
        ? Math.max(1, data.selectedQuestionIds?.length || 1) 
        : Math.max(1, data.totalQuestions || 1),
      timeLimit: data.enableTimeLimit ? data.timeLimitMinutes : null,
      startsAt: data.startsAt || null,
      endsAt: data.endsAt || null,
      passMark: data.passMark,
      isShuffle: data.shuffleQuestions,
      showResults: data.showResults,
      gradeLabels: data.gradeLabels.map((l: any) => ({ name: l.grade, min: l.minPercent })),
      selectionRules: data.questionSelection === "DYNAMIC" ? {
        source: data.selectedBankId ? "bank" : "topic",
        bankId: data.selectedBankId || undefined,
        total: data.totalQuestions,
        distribution: {
          easy: data.selectionRules.find((r: any) => r.difficulty === "Easy")?.count || 0,
          medium: data.selectionRules.find((r: any) => r.difficulty === "Medium")?.count || 0,
          hard: data.selectionRules.find((r: any) => r.difficulty === "Hard")?.count || 0,
        }
      } : undefined,
    };
    await apiClient.patch(`/assessments/${id}/settings`, settingsPayload);

    // 3. Update questions (skip if published/archived as backend blocks it)
    if (!isPublishedOrArchived && data.questionSelection === "MANUAL" && data.selectedQuestionIds && data.selectedQuestionIds.length > 0) {
      await apiClient.put(`/assessments/${id}/questions`, {
        questionIds: data.selectedQuestionIds,
      });
    }

    // 4. Handle status transitions if changed
    if (data.status) {

      if (originalStatus === "DRAFT" && data.status === "PUBLISHED") {
        await apiClient.post(`/assessments/${id}/publish`, {});
      } else if (originalStatus === "PUBLISHED" && data.status === "ARCHIVED") {
        await apiClient.post(`/assessments/${id}/archive`, {});
      }
    }

    revalidatePath(`/assessments/${id}`);
    revalidatePath("/assessments");
    revalidatePath("/search");
    revalidatePath("/");
    return { success: true, assessment: updatedAssessment };
  } catch (error: any) {
    console.error("Failed to update assessment:", error);
    return { success: false, error: error.message || "Failed to update assessment" };
  }
}

