export function resolveLeaderboardRound(
  leaderboard: LeaderboardEntry[],
  roundIndex: number,
): LeaderboardEntry[] {
  const updated = leaderboard.map((entry, index) => {
    const answeredCorrectly = ((index * 2 + roundIndex + 1) % 4) !== 0;
    const streak = answeredCorrectly ? entry.streak + 1 : 0;
    const streakBonus = streak >= 2 ? 35 + (streak - 2) * 15 : 0;
    const speedBonus = answeredCorrectly ? Math.max(15, 70 - index * 8 - roundIndex * 6) : 0;
    const lastGain = answeredCorrectly ? 100 + roundIndex * 20 + speedBonus + streakBonus : 0;

    return {
      ...entry,
      score: entry.score + lastGain,
      streak,
      lastGain,
      previousRank: entry.rank,
    };
  });

  return updated
    .sort((left, right) => right.score - left.score)
    .map((entry, index) => ({
      ...entry,
      rank: index + 1,
    }));
}

export function buildDistribution(
  options: QuestionOption[],
  answeredCount: number,
  correctOptionId: string,
) {
  const base = options.map((option, index) => {
    const weight = option.id === correctOptionId ? 0.38 : 0.18 + index * 0.06;
    return {
      optionId: option.id,
      count: Math.max(0, Math.round(answeredCount * weight)),
    };
  });

  const total = base.reduce((sum, item) => sum + item.count, 0);
  const remainder = Math.max(0, answeredCount - total);

  if (base[0]) {
    base[0].count += remainder;
  }

  return base;
}

export function formatDurationClock(totalSeconds: number) {
  const hours = Math.floor(totalSeconds / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;

  if (hours > 0) {
    return `${hours}:${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`;
  }

  return `${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`;
}

export function hasAnswerResponse(question: QuestionRound | undefined, value: QuestionRendererValue) {
  if (!question) return false;

  const rendererType = normalizeQuestionRendererType(question.type);

  if (rendererType === "matching") {
    if (typeof value !== "object" || value === null || Array.isArray(value)) return false;
    const raw = question.rawOptions;
    const leftOptions = raw?.leftSide || [];
    // Count how many values have an actual rightId selected
    const matchedCount = Object.values(value).filter((v) => String(v).trim().length > 0).length;
    // Must match all left options
    return matchedCount === leftOptions.length && leftOptions.length > 0;
  }

  // Fallback for others
  if (Array.isArray(value)) {
    return value.length > 0;
  }

  if (typeof value === "object" && value !== null) {
    return Object.values(value).some((item) => String(item).trim().length > 0);
  }

  if (typeof value === "string") {
    return value.trim().length > 0;
  }

  if (typeof value === "number" || typeof value === "boolean") {
    return true;
  }

  return false;
}

export function isCorrectAnswerResponse(question: QuestionRound, value: QuestionRendererValue) {
  const rendererType = normalizeQuestionRendererType(question.type);

  if (rendererType === "ordering") {
    if (!Array.isArray(value)) return false;

    // Use correctAnswers.sequence from API if available
    const sequence = question.correctAnswers?.sequence;
    if (Array.isArray(sequence)) {
      return value.length === sequence.length && value.every((id, index) => id === sequence[index]);
    }

    // Fallback: compare against options array order
    return (
      value.length === question.options.length &&
      value.every((optionId, index) => optionId === question.options[index]?.id)
    );
  }

  if (rendererType === "matching") {
    if (typeof value !== "object" || value === null || Array.isArray(value)) {
      return false;
    }

    // Use correctAnswers.pairs from API if available
    const pairs = question.correctAnswers?.pairs;
    if (Array.isArray(pairs)) {
      return pairs.every(
        (pair: any) => value[pair.leftId] === pair.rightId,
      );
    }

    // Fallback: use rawOptions leftSide/rightSide
    const raw = question.rawOptions;
    if (raw?.leftSide && raw?.rightSide) {
      return raw.leftSide.every(
        (left: any, index: number) => value[left.id] === raw.rightSide[index]?.id,
      );
    }

    return false;
  }

  if (rendererType === "fill") {
    if (typeof value !== "object" || value === null || Array.isArray(value)) return false;
    const acceptedAnswers = question.correctAnswers?.answers;
    if (!Array.isArray(acceptedAnswers)) return false;

    let isCorrect = true;
    acceptedAnswers.forEach((accepted: any, index: number) => {
      const given = (String((value as Record<string, string>)[index] || "")).trim().toLowerCase();
      const isMatch = Array.isArray(accepted) && accepted.some((a: string) => a.trim().toLowerCase() === given);
      if (!isMatch) isCorrect = false;
    });
    return isCorrect;
  }

  if (rendererType === "multiple") {
    if (!Array.isArray(value)) return false;
    const correctIds = question.correctAnswers?.optionIds || [question.correctOptionId];
    if (!Array.isArray(correctIds)) return false;
    return value.length === correctIds.length && value.every(id => correctIds.includes(id));
  }

  if (rendererType === "boolean") {
    if (typeof value !== "boolean") return false;
    const correctValue = question.correctAnswers?.value;
    return value === correctValue;
  }

  return typeof value === "string" && value === question.correctOptionId;
}

export function calculateQuestionScore(question: QuestionRound, value: QuestionRendererValue): number {
  const rendererType = normalizeQuestionRendererType(question.type);
  const maxScore = question.points || 0;

  if (isSubjectiveQuestion(question.type)) {
    return 0; // Handled manually
  }

  // Deductive Scoring (Partial Credit with Penalty)

  if (rendererType === "multiple") {
    if (!Array.isArray(value)) return 0;
    const correctIds = question.correctAnswers?.optionIds || [question.correctOptionId];
    if (!Array.isArray(correctIds) || correctIds.length === 0) return 0;

    const correctSelected = value.filter(id => correctIds.includes(id)).length;
    const wrongSelected = value.filter(id => !correctIds.includes(id)).length;
    const totalCorrect = correctIds.length;

    const ratio = Math.max(0, (correctSelected - wrongSelected) / totalCorrect);
    return parseFloat((ratio * maxScore).toFixed(2));
  }

  if (rendererType === "fill") {
    if (typeof value !== "object" || value === null || Array.isArray(value)) return 0;
    const acceptedAnswers = question.correctAnswers?.answers;
    if (!Array.isArray(acceptedAnswers) || acceptedAnswers.length === 0) return 0;

    let correctCount = 0;
    let emptyCount = 0;
    const totalBlanks = acceptedAnswers.length;

    acceptedAnswers.forEach((accepted: any, index: number) => {
      const given = (String((value as Record<string, string>)[index] || "")).trim().toLowerCase();
      if (!given) {
        emptyCount++;
      } else {
        const isMatch = Array.isArray(accepted) && accepted.some((a: string) => a.trim().toLowerCase() === given);
        if (isMatch) correctCount++;
      }
    });

    const pointsPerBlank = maxScore / totalBlanks;
    const correctScore = correctCount * pointsPerBlank;
    const penaltyScore = emptyCount * (pointsPerBlank * 0.5);
    const finalScore = Math.max(0, correctScore - penaltyScore);
    return parseFloat(finalScore.toFixed(2));
  }

  if (rendererType === "matching") {
    if (typeof value !== "object" || value === null || Array.isArray(value)) return 0;

    // In Preview mode, we check against correctAnswers.pairs if available
    const pairs = question.correctAnswers?.pairs;
    if (!Array.isArray(pairs) || pairs.length === 0) return 0;

    const totalPairs = pairs.length;
    let correctCount = 0;
    let emptyCount = 0;

    const correctMap = new Map(pairs.map((p: any) => [p.leftId, p.rightId]));

    Array.from(correctMap.keys()).forEach((leftId) => {
      const rightId = value[leftId];
      if (!rightId || String(rightId).trim() === "") {
        emptyCount++;
      } else if (correctMap.get(leftId) === rightId) {
        correctCount++;
      }
    });

    const pointsPerPair = maxScore / totalPairs;
    const correctScore = correctCount * pointsPerPair;
    const penaltyScore = emptyCount * (pointsPerPair * 0.5);
    const finalScore = Math.max(0, correctScore - penaltyScore);
    return parseFloat(finalScore.toFixed(2));
  }

  // Binary Scoring (All-or-Nothing)
  return isCorrectAnswerResponse(question, value) ? maxScore : 0;
}

export function getCorrectAnswerText(question: QuestionRound): string {
  const rendererType = normalizeQuestionRendererType(question.type);

  if (rendererType === "fill") {
    const acceptedAnswers = question.correctAnswers?.answers;
    if (Array.isArray(acceptedAnswers)) {
      return acceptedAnswers.map((accepted, index) => {
        const primaryAnswer = Array.isArray(accepted) ? accepted[0] : String(accepted);
        return `[Blank ${index + 1}: ${primaryAnswer}]`;
      }).join(" ");
    }
  }

  if (rendererType === "ordering") {
    const sequence = question.correctAnswers?.sequence;
    if (Array.isArray(sequence)) {
      return sequence.map(id => question.options.find((opt: any) => opt.id === id)?.text ?? id).join(" → ");
    }
  }

  if (rendererType === "matching") {
    const pairs = question.correctAnswers?.pairs;
    const raw = question.rawOptions;
    const leftOpts = raw?.leftSide || raw?.left;
    const rightOpts = raw?.rightSide || raw?.right;

    if (Array.isArray(pairs) && leftOpts && rightOpts) {
      return pairs.map((pair: any) => {
        const left = leftOpts.find((opt: any) => opt.id === (pair.leftId || pair.left))?.text;
        const right = rightOpts.find((opt: any) => opt.id === (pair.rightId || pair.right))?.text;
        return `${left} → ${right}`;
      }).join(", ");
    }
  }

  if (rendererType === "multiple") {
    const optionIds = question.correctAnswers?.optionIds;
    if (Array.isArray(optionIds)) {
       return optionIds.map(id => question.options.find((opt: any) => opt.id === id)?.text ?? id).join(", ");
    }
  }

  if (rendererType === "boolean") {
    return question.correctAnswers?.value ? "True" : "False";
  }

  if (rendererType === "essay" || rendererType === "short") {
    return typeof question.correctAnswers?.value === "string" 
      ? question.correctAnswers.value 
      : question.correctAnswers?.modelAnswerReference || "N/A";
  }

  if (rendererType === "rating") {
    return "N/A";
  }

  return question.options?.find((option: any) => option.id === question.correctOptionId)?.text || "N/A";
}

export function getAnswerResponseText(question: QuestionRound, value: QuestionRendererValue) {
  if (typeof value === "string") {
    const selectedOption = question.options?.find((option: any) => option.id === value);
    return selectedOption ? (selectedOption.label ? `${selectedOption.label}. ${selectedOption.text}` : selectedOption.text) : value;
  }

  if (Array.isArray(value)) {
    const separator = normalizeQuestionRendererType(question.type) === "ordering" ? " → " : ", ";
    return value
      .map((id) => question.options?.find((option: any) => option.id === id)?.text ?? id)
      .join(separator);
  }

  if (typeof value === "boolean") {
    return value ? "True" : "False";
  }

  if (typeof value === "number") {
    return `${value}`;
  }

  if (typeof value === "object" && value !== null) {
    const rendererType = normalizeQuestionRendererType(question.type);

    if (rendererType === "matching") {
      const raw = question.rawOptions;
      const leftOptions = raw?.leftSide || raw?.left || [];
      const rightOptions = raw?.rightSide || raw?.right || [];

      return leftOptions
        .map((leftOption: any) => {
          const rightId = value[leftOption.id] || value[leftOption.id];
          const rightOption = rightOptions.find((opt: any) => opt.id === rightId);
          return `${leftOption.text} → ${rightOption?.text ?? "No match"}`;
        })
        .join(", ");
    }

    if (rendererType === "fill") {
      const v = value as Record<string, string>;
      return Object.entries(v)
        .map(([index, text]) => `[Blank ${Number(index) + 1}: ${text}]`)
        .join(" ");
    }

    return Object.values(value).join(", ");
  }

  return "No answer";
}

export function buildPreviewAnswerValue(question: QuestionRound, index: number): QuestionRendererValue {
  const rendererType = normalizeQuestionRendererType(question.type);

  switch (rendererType) {
    case "multiple":
      return question.options.slice(0, 2).map((option: any) => option.id);
    case "boolean":
      return index % 2 === 0;
    case "short":
      return "Sample short response";
    case "essay":
      return "Sample long-form response describing the participant's thinking.";
    case "rating":
      return 4;
    case "ordering":
      return [...question.options].reverse().map((option) => option.id);
    case "fill":
      return { "0": "contact", "1": "24" };
    case "matching":
      return {
        [question.options[0]?.id ?? ""]: question.options[2]?.id ?? "",
        [question.options[1]?.id ?? ""]: question.options[3]?.id ?? "",
      };
    case "file":
      return "supporting-evidence.pdf";
    default:
      return question.options[index % question.options.length]?.id ?? null;
  }
}

export function isSubjectiveQuestion(type: string) {
  const normalized = normalizeQuestionRendererType(type);
  return ["short", "essay", "rating", "file"].includes(normalized);
}

